  // Auto-generated — regenerate with: loft scripts/build-playground-examples.loft
  export const EXAMPLES = {      "loft_language": "fn main() {\n  // Variables are declared by assigning a value — no 'let', 'var', or type annotation.\n  // The type is inferred: greeting is text, x and y are integers.\n  greeting = \"Hello, Loft!\";\n  x = 6;\n  y = 7;\n  assert(x * y == 42, \"Arithmetic works as you would expect\");\n  // Format strings use '{expression}' — you can embed any expression, not just names.\n  assert(\"{greeting} The answer is {x * y}.\" == \"Hello, Loft! The answer is 42.\", \"Format strings interpolate expressions\");\n  // ## Null in practice\n  // Dividing by zero produces null instead of crashing.\n  // In a condition, null is treated as false, so '!' turns it into true.\n  // This makes it easy to handle unexpected values gracefully.\n  zero = 0;\n  result = 12 / zero;\n  assert(!result, \"Dividing by zero gives null, which is false-like\");\n  // ## if is an expression\n  // Every 'if/else' can be used on the right side of an assignment.\n  // The value of the chosen branch becomes the value of the whole expression.\n  label = if x * y == 42 {\n    \"correct\"\n  } else {\n    \"wrong\"\n  };\n  assert(label == \"correct\", \"if-expression picked the right branch\");\n  // ## A quick taste of collections\n  // A vector is an ordered list of values.\n  // Fill it with a list literal using square brackets.\n  // Access elements by 0-based index.\n  // 'len()' tells you how many elements there are.\n  scores =[10, 20, 30, 40];\n  assert(scores[2] == 30, \"0-based indexing: element 2 is 30\");\n  assert(len(scores) == 4, \"len counts elements\");\n  total = 0;\n  for s in scores {\n    total += s;\n  }\n  assert(total == 100, \"Summed all scores: {total}\");\n}",
          "keywords": "fn main() {\n  // ## Conditionals\n  // 'if' runs a block only when its condition is true. If the condition is\n  // false the block is skipped entirely — nothing else happens.\n  // 'panic' stops the program immediately with a message. During development\n  // it is a clear way to mark situations that should never occur.\n  if 2 > 5 {\n    panic(\"Incorrect test\");\n  }\n  // Combine conditions with 'and' / 'or' (or their symbol equivalents '&&' / '||').\n  // Note that '&' is the bitwise AND operator — it works on the individual\n  // 1s and 0s inside a number, which is different from the logical 'and' keyword\n  // that works on true/false values.\n  // An 'if/else' chain picks exactly one branch to execute.\n  a = 12;\n  if a > 10 and a & 7 == 4 {\n    a += 1;\n  } else {\n    a -= 1;\n  }\n  // Text enclosed in double quotes can contain expressions inside curly braces —\n  // the expression is evaluated and its result is inserted into the text.\n  // 'assert' checks that its first argument is true; if it is false the\n  // second argument is printed as an error message.\n  assert(a == 13, \"Incorrect value {a} != 13\");\n  // ## if as an expression\n  // Every block in Loft produces a value — the last expression inside it.\n  // That means you can use 'if/else' on the right-hand side of an assignment,\n  // picking between two values based on a condition. No ternary operator needed.\n  b = if a == 13 {\n    \"Correct\"\n  } else {\n    \"Wrong\"\n  };\n  assert(b == \"Correct\", \"Logic expression\");\n  // ## Iteration\n  // 'for x in a..b' loops over the integers starting at a and stopping\n  // before b (exclusive upper bound). Use '..=' to include the upper bound.\n  // Here we sum 1 + 2 + 3 + 4 + 5 = 15.\n  t = 0;\n  for a in 1..6 {\n    t += a;\n  }\n  assert(t == 15, \"Total was {t} instead of 15\");\n  // 'rev(range)' reverses the direction of any range.\n  // '1..=5' is inclusive, so it visits 5, 4, 3, 2, 1 in that order.\n  // Multiplying each digit into a running total builds the number 54321.\n  t = 0;\n  for a in rev(1..=5) {\n    t = t * 10 + a;\n  }\n  assert(t == 54321, \"Result was {t} instead of 54321\");\n  // ## Nested loops and break\n  // Loft has no 'while' or 'loop' keyword — all repetition uses 'for' with a\n  // range, so there is always a clear upper bound on how many iterations can occur.\n  // 'break' exits the nearest enclosing loop immediately.\n  // To exit an outer loop from inside an inner one, write 'outerVar#break'.\n  // Here x#break leaves both loops when the product x*y reaches 16.\n  b = \"\";\n  for x in 1..5 {\n    for y in 1..5 {\n      if y > x {\n        break;\n        // this breaks the inner y loop\n      }\n      if x * y >= 16 {\n        x# break;\n      }\n      if len(b) > 0 {\n        b += \"; \";\n      }\n      b += \"{x}:{y}\";\n    }\n  }\n  assert(b == \"1:1; 2:1; 2:2; 3:1; 3:2; 3:3; 4:1; 4:2; 4:3\", \"Incorrect sequence '{b}'\");\n  // ## Loop helpers: #first and #count\n  // Inside a loop body you have access to some useful metadata about the\n  // current iteration. 'x#first' is true only for the very first element\n  // that passes the filter. 'x#count' is a zero-based index counting only\n  // the elements that were not filtered out.\n  // An 'if' clause directly after 'in range' filters which values enter the loop —\n  // here we skip every value where x % 3 == 1, keeping 2, 3, 5, 6, 8, 9.\n  b = \"\";\n  for x in 1..=9 if x % 3 != 1 {\n    if !x#first {\n      b += \", \";\n    }\n    b += \"{x#count}:{x}\";\n  }\n  assert(b == \"0:2, 1:3, 2:5, 3:6, 4:8, 5:9\", \"Sequence '{b}'\");\n  // ## Formatting a loop inline\n  // A for loop can appear inside a format string. The results are collected\n  // into a bracketed, comma-separated list. A format specifier after the\n  // closing brace is applied to every element — ':02' means at least 2 digits,\n  // zero-padded. This is handy for building compact representations on the fly.\n  assert(\"a{for x in 1..7 {x*2}:02}b\" == \"a[02,04,06,08,10,12]b\", \"Format range\");\n}",
          "texts": "fn main() {\n  // ## Joining and measuring text\n  // Use '+' to join two pieces of text into one. The result is a new value —\n  // neither of the originals is modified.\n  // Placing a value name inside curly braces inside a format string inserts\n  // the value as text. You can also control the width: '{a:4}' pads the\n  // value on the right to at least 4 characters.\n  a = \"1\" + \"2\";\n  assert(\"'{a:4}'\" == \"'12  '\", \"Formatting text\");\n  assert(len(a + \"123\") == 5, \"Text length\");\n  // 'len()' counts bytes, not visible characters.\n  // An emoji like '😃' takes 4 bytes in UTF-8, a heart symbol '♥' takes 3,\n  // and every plain ASCII letter takes exactly 1. Keep this in mind whenever\n  // you use len() to check how \"long\" something is to a human reader.\n  assert(len(\"😃\") == 4, \"Emoji byte length\");\n  assert(len(\"♥\") == 3, \"Heart byte length\");\n  assert(len(\"abc\") == 3, \"ASCII byte length\");\n  // ## Reading individual characters\n  // Square brackets with a single byte index give you the character at that\n  // position. For plain ASCII text every byte is one character, so indexing\n  // by position is straightforward. Loft will return the full character\n  // even if it spans multiple bytes.\n  s = \"ABCDE\";\n  assert(s[0] == 'A', \"Character at byte 0\");\n  assert(s[2] == 'C', \"Character at byte 2\");\n  // ## Slicing text\n  // A slice 's[start..end]' gives you the bytes from 'start' up to but not\n  // including 'end'. You can omit the start to begin at 0, or omit the end\n  // to go all the way to the last byte. Loft snaps offsets to valid character\n  // boundaries so you can never accidentally cut a multi-byte character in half.\n  assert(s[0..2] == \"AB\", \"Explicit start slice\");\n  assert(s[..2] == \"AB\", \"Open-start slice\");\n  assert(s[1..4] == \"BCD\", \"Sub-string by byte range\");\n  assert(s[3..] == \"DE\", \"Open-ended sub-string\");\n  // A negative end index counts backwards from the end of the text.\n  // '-1' means \"stop one byte before the very last byte\". Combined with a\n  // start offset this lets you trim a known suffix without knowing the exact length.\n  txt = \"12😊🙃45\";\n  assert(txt[2..- 1] == \"😊🙃4\", \"UTF-8 sub-string by byte range\");\n  // ## Iterating over characters\n  // A 'for' loop over a text value visits one character at a time,\n  // even when characters span multiple bytes. Two loop helpers give you\n  // position information without any extra code:\n  // 'c#index' is the byte offset where the current character starts.\n  // 'c#next' is the byte offset immediately after the current character ends.\n  // This makes it easy to build a byte-offset map or to collect characters\n  // starting from a specific position.\n  result = \"\";\n  positions =[];\n  nexts =[];\n  for c in \"Hi 😊!\" {\n    positions +=[c#index];\n    nexts +=[c#next];\n    if c#index >= 3 {\n      result += c;\n    }\n  }\n  assert(result == \"😊!\", \"Character iteration was {result}\");\n  assert(\"{positions}\" == \"[0,1,2,3,7]\", \"Character positions was {positions}\");\n  assert(\"{nexts}\" == \"[1,2,3,7,8]\", \"Character nexts was {nexts}\");\n  // ## Searching inside text\n  // These built-in functions answer common \"does this text contain…?\" questions.\n  // 'starts_with' and 'ends_with' check the boundaries.\n  // 'find' returns the byte offset of the first match, or null if not found.\n  // 'contains' is true if the needle appears anywhere in the text.\n  // All positions are byte offsets, consistent with 'len()' and slicing.\n  assert(\"something\".starts_with(\"some\"), \"starts_with\");\n  assert(\"something\".ends_with(\"thing\"), \"ends_with\");\n  assert(\"something\".find(\"th\") == 4, \"find returns byte offset\");\n  assert(\"a longer text\".contains(\"longer\"), \"contains\");\n  // 'trim()' removes spaces and other whitespace from both ends of a text value.\n  // It is useful when reading user input or parsing text from a file.\n  assert(trim(\"  hello  \") == \"hello\", \"trim\");\n  // ## Escaping braces in format strings\n  // Inside a format string '{' and '}' are special: they introduce an\n  // interpolated expression. To include a literal brace in the output,\n  // double it: '{{' produces '{' and '}}' produces '}'.\n  brace_inner = \"cd\";\n  assert(\"ab{{cd}}e\" == \"ab{{{brace_inner}}}e\", \"Escaping braces\");\n  // ## Aligning text in a fixed-width field\n  // The ':' specifier controls alignment and width. '<' left-aligns the value,\n  // '>' right-aligns it (the default). The width can be a constant or a small\n  // arithmetic expression — here '2+3' evaluates to 5, giving a field of width 5.\n  vr = \"abc\";\n  assert(\"1{vr:<2+3}2{vr}3{vr:6}4{vr:>7}\" == \"1abc  2abc3abc   4    abc\", \"Text alignment\");\n}",
          "integers": "fn main() {\n  // ## Converting between numbers and text\n  // Wrapping a value in '{...}' inside a string formats it as text.\n  // Going the other way, 'as integer' parses a text value into a number.\n  // If the text cannot be parsed, the result is null — not a crash.\n  v = 4;\n  assert(\"{v}\" == \"4\", \"Format integer as text\");\n  assert(\"123\" as integer == 123, \"Parse text to integer\");\n  assert(!(\"abc\" as integer), \"Unparseable text gives null\");\n  // ## Arithmetic and operator precedence\n  // Loft follows standard mathematical precedence: '*' and '/' before '+' and '-'.\n  // Bitwise operators (<<, &, ^) have their own precedence — when mixing them with\n  // arithmetic, parentheses make your intent clear and avoid surprises.\n  // Note: '^' is XOR, not exponentiation. Use pow(base, exp) for powers.\n  assert(1 + 2 * 4 == 9, \"Multiplication before addition\");\n  assert(1 + 2 << 2 == 12, \"Shift: (1+2) << 2 = 12\");\n  assert(0x0a8 & 15 == 8, \"Bitwise AND masks low 4 bits\");\n  assert(42 ^ 0b111111 == 21, \"Bitwise XOR\");\n  assert(105 % 100 == 5, \"Modulus (remainder)\");\n  assert(pow(2.0, 3.0) == 8.0, \"pow() for exponentiation\");\n  // 'abs()' returns the absolute value — the distance from zero, always positive.\n  assert(1 + abs(-2) == 3, \"abs(-2) == 2\");\n  // ## Division by zero produces null, not a crash\n  // Most languages crash or throw an exception on division by zero.\n  // Loft produces null instead, which behaves like false in conditions.\n  // This lets you handle missing or bad data gracefully with a simple '!'.\n  a = 2 * 2;\n  a -= 4;\n  // a is now 0\n  assert(!(12 / a), \"Division by zero gives null\");\n  // ## Warning when you write a literal zero divisor\n  // When the divisor is a literal 0 written directly in your source code, loft\n  // warns you while reading your code (before running it), because that is almost\n  // certainly a mistake:\n  //   n / 0   // warning: Division by constant zero\n  //   n % 0   // warning: Modulo by constant zero\n  // The expression still runs and returns null — the warning is informational,\n  // not an error. Use a variable (like 'a' above) when you intentionally want\n  // null-on-zero division without a warning.\n  // ## Embedding integers in text\n  assert(\"a{12}b\" == \"a12b\", \"Integer in format string\");\n  // A full expression can appear inside '{...}', not just a variable name.\n  assert(\"a{1 + 2 * 3}b\" == \"a7b\", \"Expression in format string\");\n  // ## Number format specifiers\n  // After a ':' inside '{...}' you can control how a number is displayed:\n  //   #x  — hexadecimal with '0x' prefix\n  //   o   — octal\n  //   b   — binary\n  //   +   — always show a sign (+ or -)\n  //   N   — minimum field width (space-padded on the left)\n  //   0N  — minimum field width (zero-padded on the left)\n  assert(\"a{1+2+32:#x}b\" == \"a0x23b\", \"Hex format with 0x prefix\");\n  assert(\"{12:o}\" == \"14\", \"Octal\");\n  assert(\"{12:+4}\" == \" +12\", \"Sign and width\");\n  assert(\"{1:03}\" == \"001\", \"Zero-padded width\");\n  assert(\"{42:b}\" == \"101010\", \"Binary\");\n  // Hexadecimal literals in source code accept both lower and upper case digits.\n  assert(0xff == 255, \"Lowercase hex literal\");\n  assert(0xFF == 255, \"Uppercase hex literal\");\n  assert(0x2A == 42, \"Uppercase hex digit\");\n  // ## The 'long' type for large numbers\n  // 'long' is a 64-bit signed integer — use it when values might exceed 2 billion.\n  // Write a long literal by appending 'l': '1l', '100000000000l'.\n  // Long values support the same arithmetic and format specifiers as integer.\n  // Convert a long back to an integer with 'as integer'.\n  big = 1000000000l * 5l;\n  assert(big == 5000000000l, \"Long arithmetic\");\n  assert(\"{1l + 1:+4}\" == \"  +2\", \"Long in format string\");\n  assert(12l as integer == 12, \"Long to integer conversion\");\n  // ## Common pitfall: integer overflow\n  // If a 32-bit integer calculation overflows the max value (~2 billion),\n  // the result wraps around silently. Use 'long' when you expect large values.\n  // For example, a score that multiplies two large numbers can silently wrap.\n  // Switching to 'long' avoids this: 'score = big_a as long * big_b as long'.\n}",
          "boolean": "fn main() {\n  // A comparison produces a boolean result directly.\n  // '!' flips a boolean: true → false, false → true.\n  assert(!(3 > 2 + 4), \"3 is not greater than 6\");\n  assert(true as text == \"true\", \"Convert boolean to text\");\n  // ## Logical operators: and / or\n  // 'and' (also '&&') is true only when both sides are true.\n  // 'or'  (also '||') is true when at least one side is true.\n  // Both skip the right side when the left side already determines the result.\n  // For example, 'false and X' is always false, so X is never evaluated.\n  // This matters when the right side could produce null or has a side effect.\n  assert(1 > 0 and 2 > 1, \"Both conditions true\");\n  assert(1 > 2 or 3 > 2, \"Second condition true\");\n  assert(!(1 > 2 && 3 > 2), \"First false → whole 'and' is false\");\n  assert(!(1 > 2 || 3 > 4), \"Both false → 'or' is false\");\n  // ## Null in boolean context\n  // Division by zero (and other failed operations) produce null.\n  // Null in a boolean context is treated as false, so '!' is true.\n  // This lets you write guard clauses without a separate null-check syntax:\n  //   if !result { ... handle missing value ... }\n  zero = 0;\n  assert(!(12 / zero), \"null from division-by-zero is false-like\");\n  assert(12 > 0, \"positive integer is true\");\n  // ## Bitwise operators\n  // While 'and'/'or' work on true/false values, bitwise operators work on\n  // the individual bits of an integer. They are useful for flags, masks,\n  // and low-level data manipulation.\n  //\n  //   '&'  — keeps only bits set in BOTH operands (AND)\n  //   '|'  — keeps bits set in EITHER operand (OR)\n  //   '<<' — shift bits left N positions  (×2^N)\n  //   '>>' — shift bits right N positions (÷2^N)\n  //\n  // Tip: '&' binds less tightly than comparison operators. Use parentheses\n  // when you mix bitwise and comparison expressions in the same condition.\n  assert((0x0f & 0xa8) == 8, \"Bitwise AND: keeps only bits in both\");\n  assert((0xf0 | 0x0f) == 0xff, \"Bitwise OR: combines bits from either\");\n  assert(1 << 4 == 16, \"Left shift: 1 × 2^4 = 16\");\n  assert(256 >> 3 == 32, \"Right shift: 256 ÷ 2^3 = 32\");\n  // ## Negation\n  // '!' is the logical NOT operator. It flips any boolean expression.\n  assert(!false, \"not false is true\");\n  assert(!(1 > 2), \"not false comparison is true\");\n  // ## Formatting booleans\n  // Booleans can be embedded in a format string like any other value.\n  // The '^' alignment specifier centres the value in a field of given width.\n  // '<' aligns left, '>' aligns right (right-alignment is the default).\n  assert(\"1{true:^7}2\" == \"1 true  2\", \"Centred boolean in field of width 7\");\n  assert(\"{false}\" == \"false\", \"Plain boolean format\");\n  // ## '&' vs 'and'\n  // '&' is bitwise AND on integers; 'and' (or '&&') is logical AND on booleans.\n  // Writing 'a & b' where both sides are booleans is a compile error — the\n  // compiler requires 'and' or '&&' for boolean logic.\n  flag_a = 3 > 1;\n  // true\n  flag_b = 4 > 2;\n  // true\n  assert(flag_a and flag_b, \"Correct: logical AND on two booleans\");\n}",
          "float": "fn main() {\n  // Write a decimal point in a literal and Loft treats the whole expression as a float.\n  // The usual arithmetic operators (+, -, *, /) all work the way you would expect.\n  assert(1.5 + 0.5 == 2.0, \"Float addition\");\n  assert(3.0 / 2.0 == 1.5, \"Float division\");\n  assert(2.0 * 1.5 == 3.0, \"Float multiplication\");\n  // The 'f' suffix selects single-precision floats, which take half the memory\n  // of a regular float but have fewer decimal digits of accuracy. This trade-off\n  // is common in graphics and audio code where exact decimal values matter less\n  // than speed or memory.\n  x = 0.1f + 2 * 1.0f;\n  assert(x == 2.1f, \"Single precision float\");\n  // 'as float' converts an integer to a float so you can mix them in calculations.\n  // Putting a float inside '{...}' converts it to text for display.\n  // You can also go the other way: '\"1.5\" as float' parses the text back to a number.\n  assert(3 as float == 3.0, \"Integer to float\");\n  assert(\"1.5\" as float == 1.5, \"Text to float\");\n  assert(\"{1.5}\" == \"1.5\", \"Float formatted as text\");\n  // ## Formatting Floats\n  // Put a colon after the value inside '{...}' to control how it looks.\n  // '{value:width.precision}' — 'width' is the minimum number of characters printed\n  // (padded with spaces on the left); 'precision' fixes the number of decimal places.\n  // You can use either part on its own: '{value:.2}' just fixes decimal places,\n  // '{value:5}' just sets the minimum width.\n  assert(\"{1.2:4.2}\" == \"1.20\", \"Float with width and precision\");\n  assert(\"{334.1:.2}\" == \"334.10\", \"Float with precision only\");\n  assert(\"{1.4:5}\" == \"  1.4\", \"Float with width only\");\n  // ## Math Functions\n  // 'PI' is a built-in constant (approximately 3.14159265358979).\n  // Multiplying it by 1000 and rounding gives 3142, which confirms the value is correct.\n  assert(round(PI * 1000.0) == 3142.0, \"PI constant\");\n  // 'pow(base, exponent)' raises a number to a power — this is exponentiation.\n  // Note: '^' in Loft is bitwise XOR, NOT exponentiation. Always use pow() for powers.\n  // 'log(value, base)' is the inverse: log(x, b) answers \"b to the what power equals x?\"\n  // Here: 4^5 = 1024, and log(1024, 2) = 10 because 2^10 = 1024.\n  assert(log(pow(4.0, 5), 2) == 10.0, \"log base 2 of 4^5\");\n  // 'sin' and 'cos' work in radians, not degrees.\n  // A full circle is 2*PI radians; a half circle (180 degrees) is PI radians.\n  // sin(PI) should be exactly zero but computers use approximations for decimal\n  // numbers, so you may get something like 0.0000000001 instead. We use ceil()\n  // to round it up to 0. cos(PI) is exactly -1, so the whole expression\n  // ceil(~0 + -1 * 1000) lands at -1000.\n  assert(ceil(sin(PI) + cos(PI) * 1000) == -1000.0, \"sin and cos\");\n  // 'abs()' returns the absolute value — the distance from zero, always non-negative.\n  // Useful any time you care about magnitude but not direction.\n  assert(abs(-2.5) == 2.5, \"Absolute value of float\");\n  // 'round()' picks the nearest whole number (0.5 rounds up).\n  // 'ceil()' always rounds up to the next whole number, even for 2.01.\n  // 'floor()' always rounds down to the previous whole number, even for 2.99.\n  // All three give back a float, not an integer — so 3.0, not 3.\n  assert(round(2.6) == 3.0, \"round up\");\n  assert(round(2.4) == 2.0, \"round down\");\n  assert(ceil(2.1) == 3.0, \"ceil\");\n  assert(floor(2.9) == 2.0, \"floor\");\n  // Single-precision floats work inside format strings just like regular floats.\n  assert(\"a{0.1f + 2 * 1.0f}b\" == \"a2.1b\", \"Single-precision format\");\n}",
          "functions": "fn greet(name: text, greeting: text = \"Hello\") -> text {\n  greeting + \", \" + name + \"!\"\n}\n// ## Default arguments that involve other arguments\n// Loft defaults must be literal values, not expressions referencing other parameters.\n// When one argument's default should be derived from another, use a sentinel value\n// and compute the actual default inside the function body.\n// The convention is to use -1 (or 0) as \"not provided\" for integer parameters.\nfn substring(t: text, start: integer = 0, end: integer = -1) -> text {\n  actual_end = if end < 0 { len(t) } else { end };\n  t[start..actual_end]\n}\n// ## Named Arguments\n// When a function has several parameters with defaults, you can skip middle ones\n// by naming the arguments you want to provide. Positional arguments come first;\n// once you use a name, all remaining arguments must also be named.\nfn connect(host: text, port: integer = 8080, tls: boolean = true) -> text {\n  \"{host}:{port}:{tls}\"\n}\n// ## Reference Parameters and Defaults\n// A function with no '-> type' is called for its side effects, not its result.\n// Adding '&' before a parameter type makes it a reference: the function receives a\n// direct link to the caller's variable and can read or write it.\n// Without '&', Loft copies the value in, so changes inside the function stay local.\n// Default values (written '= value' after the type) are substituted when the caller\n// omits that argument.\n\nfn add(a:  & integer, b: integer, c: integer = 0) {\n  a += b + c;\n}\n// ## Early Return\n// Use 'return value;' to exit a function before reaching the end.\n// This is handy for guard clauses: handle the special cases first, then write the\n// normal path without extra nesting.\n\nfn classify(n: integer) -> text {\n  if n < 0 {\n    return \"negative\";\n  }\n  if n == 0 {\n    return \"zero\";\n  }\n  \"positive\"\n}\n// ## Const and Reference Parameters\n// 'const' on a parameter tells the compiler \"this function must never change this value.\"\n// The compiler enforces it — any assignment to a const parameter is a compile error.\n// '&' is the opposite promise: \"this function will modify this value.\"\n// Declaring '&' without actually writing to the parameter is also a compile error.\n// These rules make it easy to read a function signature and know what it does to its inputs.\n\nfn scale(a: integer, factor: integer) -> integer {\n  a * factor\n}\n// ## Type-Based Dispatch\n// You can define two functions with the same name as long as their parameter types differ.\n// Loft picks the right one at compile time based on the type of the argument you pass.\n\nfn describe_int(v: integer) -> text {\n  \"integer:{v}\"\n}\n\nfn describe_text(v: text) -> text {\n  \"text:{v}\"\n}\n// ## Function References\n// 'fn <name>' creates a reference to a named function that you can store or pass around.\n// The compiler checks that the name exists and is a function — a typo is a compile error.\n// The result has type 'fn(param_types) -> return_type' and can be:\n//   - stored in a variable,\n//   - called directly with 'f(args)', and\n//   - passed as a parameter to another function.\n\nfn double_it(x: integer) -> integer {\n  x * 2\n}\n\nfn negate_it(x: integer) -> integer {\n  - x\n}\n\nfn apply_fn(f:  fn(integer) -> integer, x: integer) -> integer {\n  f(x)\n}\n\n// ## Lambda Expressions\n// A lambda is an anonymous (unnamed) function written right where you need it.\n// Use the full form when you want to be explicit about types:\n//   fn(param: type) -> return_type { body }\n// Use the short form (pipe-bar syntax) when the call site already knows the types:\n//   |param| { body }\n// Both forms work anywhere a function reference is expected — especially with\n// map, filter, and reduce.  The short form does not allow type annotations;\n// use the full fn(…) form when you need explicit types.\n// Lambdas that need outer variables can capture them: see the Closures page.\n\n\nfn main() {\n  // Passing both arguments explicitly overrides the default.\n  assert(greet(\"World\", \"Hi\") == \"Hi, World!\", \"Explicit argument\");\n  // Leaving out the second argument causes Loft to use the default \"Hello\".\n  assert(greet(\"World\") == \"Hello, World!\", \"Default argument\");\n  // 'add' takes 'a' by reference, so every call updates the original variable 'v'.\n  // Watch how v accumulates: 1 -> 3 -> 8.\n  v = 1;\n  add(v, 2);\n  // v = 1 + 2 = 3\n  add(v, 4, 1);\n  // v = 3 + 4 + 1 = 8\n  assert(v == 8, \"Reference parameter: {v}\");\n  // 'classify' uses early returns to handle each case separately.\n  assert(classify(-5) == \"negative\", \"Classify negative\");\n  assert(classify(0) == \"zero\", \"Classify zero\");\n  assert(classify(3) == \"positive\", \"Classify positive\");\n  // 'scale' marks both parameters 'const', so the compiler verifies they are not changed.\n  assert(scale(3, 7) == 21, \"scale(3,7)\");\n  // Loft selects the right function based on the type of the argument.\n  assert(describe_int(42) == \"integer:42\", \"Integer describe\");\n  assert(describe_text(\"hi\") == \"text:hi\", \"Text describe\");\n  // A function reference is stored in a variable with type 'fn(...) -> ...'.\n  // Calling it looks exactly like a regular function call.\n  f = double_it;\n  assert(f(5) == 10, \"fn-ref stored and called: {f(5)}\");\n  // Pass function references as arguments to higher-order functions.\n  assert(apply_fn(double_it, 7) == 14, \"fn-ref as arg (double)\");\n  assert(apply_fn(negate_it, 3) == -3, \"fn-ref as arg (negate)\");\n\n  // Lambdas with map, filter, and reduce.\n  // Use |...| short form — types are inferred from the call site.\n  nums = [1, 2, 3, 4, 5];\n  doubled = map(nums, |x| { x * 2 });\n  assert(doubled[0] == 2, \"lambda map first element\");\n  assert(doubled[4] == 10, \"lambda map last element\");\n\n  // filter keeps only elements where the lambda returns true.\n  evens = filter(nums, |x| { x % 2 == 0 });\n  assert(evens[0] == 2, \"filter evens first\");\n  assert(evens[1] == 4, \"filter evens second\");\n\n  // reduce collapses the whole list into one value.\n  // The lambda receives the running total (acc) and the next element (x).\n  total = reduce(nums, 0, |acc, x| { acc + x });\n  assert(total == 15, \"reduce sum: {total}\");\n\n  // Use fn(...) long form when you need explicit types — for example\n  // when storing a lambda in a variable or passing it without call-site context.\n  negate = fn(x: integer) -> integer { -x };\n  assert(negate(7) == -7, \"stored lambda: {negate(7)}\");\n  assert(apply_fn(|x| { x * x }, 6) == 36, \"lambda as arg: 6^2\");\n\n  // --- Named arguments ---\n  assert(connect(\"example.com\") == \"example.com:8080:true\", \"all defaults\");\n  assert(connect(\"example.com\", tls: false) == \"example.com:8080:false\", \"skip port\");\n  assert(connect(host: \"example.com\", tls: false) == \"example.com:8080:false\", \"all named\");\n  assert(connect(\"example.com\", port: 443, tls: false) == \"example.com:443:false\", \"mixed\");\n  assert(greet(name: \"World\") == \"Hello, World!\", \"named with default greeting\");\n\n  // --- Default argument that depends on another argument ---\n  // 'end' defaults to -1 (sentinel); inside the body it becomes len(t).\n  assert(substring(\"hello\", 1, 3) == \"el\", \"explicit start and end\");\n  assert(substring(\"hello\", 2) == \"llo\", \"end defaults to len(t)\");\n  assert(substring(\"hello\") == \"hello\", \"both defaults\");\n}",
          "vector": "fn triple(x: integer) -> integer {\n  x * 3\n}\n\nfn is_even_n(x: integer) -> boolean {\n  x % 2 == 0\n}\n\nfn sum_acc(acc: integer, x: integer) -> integer {\n  acc + x\n}\n\nfn mul_acc(acc: integer, x: integer) -> integer {\n  acc * x\n}\n\nfn main() {\n  // Create a vector with a literal and loop over it with 'for'.\n  // Two special loop annotations help when you need to know where you are:\n  //   'v#first'  is true only on the very first iteration — useful for skipping separators.\n  //   'v#index'  holds the zero-based position of the current element.\n  x =[1, 3, 6, 9];\n  b = \"\";\n  for v in x {\n    if !v#first {\n      b += \" \";\n    }\n    b += \"{v#index}:{v}\"\n  }\n  assert(b == \"0:1 1:3 2:6 3:9\", \"result {b}\");\n  // '+=' appends another vector to the end of an existing one.\n  // You can filter and delete elements in a single pass:\n  //   Add 'if condition' after 'in vector' to visit only matching elements.\n  //   Write 'v#remove' inside the loop body to delete the current element.\n  // Here we keep only multiples of 3 by removing everything else.\n  // Note: you cannot append to a vector (v += [...]) while iterating over it —\n  // that is a compile error because the loop would then visit the new elements too,\n  // which could loop forever.\n  x +=[12, 14, 15];\n  for v in x if v % 3 != 0 {\n    v#remove;\n  }\n  assert(\"{x}\" == \"[3,6,9,12,15]\", \"result {x}\");\n  // ## Clearing\n  // 'v.clear()' removes all elements, setting the length to 0.\n  // The underlying storage is kept so appending afterwards is efficient.\n  x.clear();\n  assert(x.len() == 0, \"clear empties the vector\");\n  x += [99];\n  assert(x[0] == 99, \"append after clear works\");\n  // ## Slicing\n  // A slice gives you a window into part of a vector without copying it.\n  // 'v[a..b]' contains elements at positions a, a+1, ..., b-1 (b is excluded).\n  // 'v[a..]'  goes from position a to the very last element.\n  // 'v[..b]'  goes from the beginning up to (but not including) position b.\n  pows =[1, 2, 4, 8, 16];\n  assert(\"{pows[1..3]}\" == \"[2,4]\", \"Sub-vector\");\n  assert(\"{pows[3..]}\" == \"[8,16]\", \"Open-ended sub-vector\");\n  assert(\"{pows[..3]}\" == \"[1,2,4]\", \"Open-start sub-vector\");\n  // Accessing an index that does not exist is safe: Loft returns null instead of crashing.\n  // You can check for null with '!' (logical not) because null is falsy.\n  assert(!pows[10], \"Out-of-bounds access returns null\");\n  // ## Comprehensions\n  // A comprehension is a concise way to build a new vector from a formula.\n  // Syntax: '[for variable in range { expression }]'\n  // Add 'if condition' to include only elements that satisfy the condition.\n  // This is much shorter than creating an empty vector and appending in a loop.\n  evens =[for n in 1..10 if n % 2 == 0 {\n    n\n  }];\n  assert(\"{evens}\" == \"[2,4,6,8]\", \"Filtered comprehension\");\n  doubled =[for n in 1..6 {\n    n * 2\n  }];\n  assert(\"{doubled}\" == \"[2,4,6,8,10]\", \"Doubled comprehension\");\n  // Embedding a for loop directly inside a format string '{...}' produces a formatted list.\n  // The format specifier after ':' is applied to every element in the result.\n  // ':02' means \"at least 2 digits wide, padded with zeros on the left\".\n  assert(\"{for n in 1..7 {n*2}:02}\" == \"[02,04,06,08,10,12]\", \"Formatted vector loop\");\n  // ## Reverse Iteration\n  // Wrap a range in 'rev()' to step through elements from the last index to the first.\n  // 'rev(0..=3)' covers indices 0, 1, 2, 3 — the '=' makes the upper end inclusive.\n  // Here we visit pows[3]=8, pows[2]=4, pows[1]=2, pows[0]=1, building 8421 digit by digit.\n  c = 0;\n  for e in pows[rev(0..=3)] {\n    c = c * 10 + e;\n  }\n  assert(c == 8421, \"Reverse sub-vector iteration\");\n  // You can fill a vector with many copies of the same value using '; count' syntax:\n  //   [SomeStruct { field: value }; 16]\n  // This creates 16 identical copies in one expression. See 08-struct.loft for examples.\n  // ## Passing vectors to functions\n  //\n  // When you pass a vector to a function, the function receives a **slice** — a\n  // start position and a length inside the storage of the caller. This is efficient\n  // because no data is copied, but it has an important consequence: the function\n  // can read and modify existing elements (because it shares the same storage),\n  // but it cannot grow or shrink the vector. Appending with '+=' inside the\n  // function creates a local copy that the caller never sees.\n  //\n  // To let a function append to the caller's vector, mark the parameter with\n  // '&'. This tells the compiler to propagate structural changes (appends,\n  // clears) back to the caller when the function returns.\n  //\n  //   fn append_one(v: &vector<integer>, x: integer) { v += [x]; }\n  //\n  // Without '&', only element-level mutations are visible to the caller:\n  //\n  //   fn set_first(v: vector<integer>, x: integer) { v[0] = x; }  // caller sees the change\n  //   fn try_push(v: vector<integer>, x: integer) { v += [x]; }   // caller does NOT see the append\n  //\n  // The same rule applies to slices: 'v[2..5]' passed to a function is a\n  // narrower window into the same storage, so element writes are visible but\n  // appends are not.\n  // ## Higher-order functions\n  // 'map' applies a function to every element and returns a new vector.\n  nums =[1, 2, 3, 4, 5];\n  tripled = map(nums,  triple);\n  assert(\"{tripled}\" == \"[3,6,9,12,15]\", \"map triple: {tripled}\");\n  // 'filter' keeps only elements for which the predicate returns true.\n  evens2 = filter(nums,  is_even_n);\n  assert(\"{evens2}\" == \"[2,4]\", \"filter evens: {evens2}\");\n  // 'reduce' folds all elements into a single value, starting from an initial accumulator.\n  // Argument order: reduce(vector, initial_value, combiner).\n  total = reduce(nums, 0,  sum_acc);\n  assert(total == 15, \"reduce sum: {total}\");\n  product = reduce(nums, 1,  mul_acc);\n  assert(product == 120, \"reduce product: {product}\");\n  // You can chain these calls: filter first, then map, then reduce.\n  result = reduce(map(filter(nums,  is_even_n),  triple), 0,  sum_acc);\n  assert(result == 18, \"filter+map+reduce: {result}\");\n}",
          "structs": "struct Product {\n  name: text,\n  price: integer,\n  stock: integer\n}\n// ## Field Constraints\n// You can restrict what values a field may hold.\n// 'limit(min, max)' rejects any value outside that range at runtime.\n// 'not null' tells the field that zero is a real data value — without it, zero\n// is treated as \"no value\" (null). Colour channels can all be zero (pure black\n// is a valid colour), so all three need 'not null'.\n// Fields you omit in a constructor receive zero (or null for nullable fields) by default.\n\nstruct Colour {\n  r: integer limit(0, 255) not null,\n  g: integer limit(0, 255) not null,\n  b: integer limit(0, 255) not null\n}\n// ## Methods\n// A method is a function whose first parameter is named 'self'.\n// Loft uses the type of 'self' to decide which struct the method belongs to.\n// Call it with dot notation: 'c.to_hex()'.\n// A method can read fields via 'self.field' and return any type.\n\nfn to_hex(self: Colour) -> integer {\n  self.r * 0x10000 + self.g * 0x100 + self.b\n}\n// A method can also return a completely new struct value.\n// Write '-> StructName' as the return type and construct the value in the body.\n// The original struct is not modified — the caller gets a brand-new copy.\n\nfn dimmed(self: Colour) -> Colour {\n  Colour {r: self.r / 2, g: self.g / 2, b: self.b / 2 }\n}\n// ## Defaults and Computed Fields\n// Write '= expression' after the type to set a stored default, filled at construction.\n// Use 'computed(expression)' for a field that recalculates every time you read it —\n// it takes no space in the record and always reflects the current state.\n// Inside both, '$' refers to the struct.\n\nstruct Item {\n  name: text,\n  name_length: integer = len($.name)\n}\n\nstruct Circle {\n  radius: float,\n  area: float computed(3.14159265 * $.radius * $.radius)\n}\n// ## Storing many structs in a vector\n// 'Area' uses smaller integer types to save memory: 'u16' holds values 0–65535,\n// and 'u8' holds values 0–255. This matters when you have millions of records\n// (such as tiles in a game map) and memory usage counts.\n\nstruct Area {\n  height: u16,\n  terrain: u8,\n  water: u8,\n  direction: u8\n}\n\nfn main() {\n  // Constructing a struct: name the fields you want to set.\n  // Fields you leave out default to zero (or null for nullable fields).\n  apple = Product {name: \"Apple\", price: 120, stock: 50 };\n  assert(apple.price == 120, \"price field: {apple.price}\");\n  assert(apple.name == \"Apple\", \"name field: {apple.name}\");\n  // You can read and write individual fields after construction.\n  apple.stock -= 1;\n  assert(apple.stock == 49, \"stock after one sale: {apple.stock}\");\n  // A field omitted from the constructor gets zero as its default.\n  col = Colour {r: 128, b: 128 };\n  assert(col.g == 0, \"omitted green channel defaults to zero\");\n  // Formatting a struct shows all fields compactly.\n  assert(\"{col}\" == \"{{r:128,g:0,b:128}}\", \"Struct compact formatting\");\n  // ':j' produces JSON output — a text format used by many web APIs and config tools.\n  assert(\"{col:j}\" == \"{{\\\"r\\\":128,\\\"g\\\":0,\\\"b\\\":128}}\", \"JSON format\");\n  // Call a method on a variable using dot notation.\n  purple = Colour {r: 128, b: 128 };\n  assert(\"{purple.to_hex():x}\" == \"800080\", \"hex method result\");\n  // You can call a method directly on a constructor expression.\n  assert(Colour {r: 255, g: 0, b: 0 }.to_hex() == 0xff0000, \"method on constructor\");\n  // 'dimmed' returns a new Colour with each channel halved.\n  // The original variable is unchanged.\n  dark = purple.dimmed();\n  assert(dark.r == 64, \"dimmed r: {dark.r}\");\n  assert(dark.b == 64, \"dimmed b: {dark.b}\");\n  assert(dark.g == 0, \"dimmed g: {dark.g}\");\n  // Stored defaults are filled once at construction time.\n  it = Item {name: \"hello\" };\n  assert(it.name_length == 5, \"stored default name_length: {it.name_length}\");\n  // computed() fields recalculate on every access — changing radius updates area.\n  ci = Circle { radius: 5.0 };\n  assert(ci.area > 78.0, \"computed area: {ci.area}\");\n  ci.radius = 10.0;\n  assert(ci.area > 314.0, \"recomputed area: {ci.area}\");\n  // Fill a vector with copies of the same struct using '; count' syntax.\n  // This creates 16 Area records, all with the same initial values.\n  map =[Area {height: 0, terrain: 1, water: 1, direction: 1 };\n  16];\n  assert(\"{map[3]}\" == \"{{height:0,terrain:1,water:1,direction:1}}\", \"tile record\");\n  map[3].height = 200;\n  assert(map[3].height == 200, \"individual tile update\");\n  // ## sizeof\n  // 'sizeof(Type)' returns the packed byte size used when the type is stored\n  // as a struct field or vector element. Range-constrained integer types like\n  // u8 and u16 report their packed size, not the 4-byte stack slot size.\n  assert(sizeof(integer) == 4, \"integer: 4 bytes\");\n  assert(sizeof(u8) == 1, \"u8: 1 byte (packed)\");\n  assert(sizeof(u16) == 2, \"u16: 2 bytes (packed)\");\n  assert(sizeof(Colour) == 3, \"Colour: 3 × u8 = 3 bytes\");\n  assert(sizeof(Area) == 5, \"Area: u16 + 3 × u8 = 5 bytes\");\n}",
          "enums": "enum Direction {\n  North,\n  East,\n  South,\n  West\n}\n// ## Enums that carry data\n// Sometimes different choices have different shapes of data.\n// A 'Circle' needs one number (radius); a 'Rect' needs two (width and height).\n// Struct enums let each variant carry its own fields, keeping all the shape\n// kinds in one type while still letting you work with each variant naturally.\n\nenum Shape {\n  Circle {radius: float },\n  Rect {width: float, height: float }\n}\n// ## Methods that work on any variant\n// Write the same function name for each variant, each taking 'self' of that\n// variant's type. Loft automatically picks the right version at runtime based\n// on which variant is actually stored in the variable.\n// This lets you call shape.area() without caring which kind of shape it is.\n\nfn area(self: Circle) -> float {\n  PI * pow(self.radius, 2)\n}\n\nfn area(self: Rect) -> float {\n  self.width * self.height\n}\n// Polymorphic methods can return text just as well as numbers.\n// Each variant can produce its own human-readable description.\n\nfn describe(self: Circle) -> text {\n  \"circle with radius {self.radius}\"\n}\n\nfn describe(self: Rect) -> text {\n  \"rect {self.width} by {self.height}\"\n}\n// ## Enum methods\n// Plain enum variants can also have methods. The 'self' parameter carries the\n// current direction value, and the method can return any type.\n// Here 'opposite()' flips North↔South and East↔West.\n\nfn opposite(self: Direction) -> Direction {\n  if self == North {\n    South\n  } else if self == South {\n    North\n  } else if self == East {\n    West\n  } else {\n    East\n  }\n}\n\nfn main() {\n  // Plain enum values are ordered by declaration position.\n  // North comes first (smallest), West comes last (greatest).\n  d = East;\n  assert(d == East, \"Enum equality\");\n  assert(d != North, \"Enum inequality\");\n  assert(d > North, \"East declared after North, so it is greater\");\n  assert(West > South, \"West declared last, so it is greatest\");\n  // Convert between text and enum in both directions.\n  assert(\"{d}\" == \"East\", \"Format plain enum as text\");\n  assert(\"West\" as Direction == West, \"Parse text to enum\");\n  // Use a plain enum method like any other method.\n  assert(d.opposite() == West, \"opposite of East is West\");\n  assert(North.opposite() == South, \"opposite of North is South\");\n  // Struct enum variants are constructed exactly like regular structs.\n  c = Circle {radius: 1.0 };\n  assert(c.radius == 1.0, \"Circle radius field\");\n  r = Rect {width: 4.0, height: 5.0 };\n  assert(r.width * r.height == 20.0, \"Rect manual area\");\n  // Calling area() on a Circle runs the Circle version;\n  // on a Rect it runs the Rect version — chosen automatically at runtime.\n  assert(round(c.area() * 1000) == round(PI * 1000), \"Circle area = PI*r^2\");\n  assert(r.area() == 20.0, \"Rect area = width*height\");\n  // describe() uses format strings with field access inside each variant's method.\n  assert(c.describe() == \"circle with radius 1\", \"describe circle: {c.describe()}\");\n  assert(r.describe() == \"rect 4 by 5\", \"describe rect: {r.describe()}\");\n  // ## Stubs for missing implementations\n  // If a variant intentionally has no implementation of a method, the compiler\n  // emits a warning. Provide an empty-body stub to silence it:\n  //   fn area(self: SomeVariant) -> float { }\n  // A stub returns null at runtime and suppresses the warning.\n\n  // ## Match expressions on enums\n  // Match picks a code path based on the active variant. You must handle\n  // every variant, or include a `_` wildcard arm that catches the rest.\n  axis = match d {\n    North | South => \"vertical\",\n    East | West => \"horizontal\"\n  };\n  assert(axis == \"horizontal\", \"or-pattern: East matches East|West\");\n\n  // When a variant has fields, name them inside braces to use them in the arm body.\n  label = match c {\n    Circle { radius } => \"r={radius}\",\n    Rect { width, height } => \"{width}x{height}\"\n  };\n  assert(label == \"r=1\", \"field destructuring in match arm\");\n\n  // ## Guard clauses\n  // An arm can have an `if` guard after the pattern. If the guard fails,\n  // matching falls through to the next arm. Because the guard can fail,\n  // a guarded arm alone does not prove the variant is handled — you still\n  // need a wildcard `_` or an unguarded arm for that variant.\n  area = match c {\n    Circle { radius } if radius > 0.0 => PI * radius * radius,\n    _ => 0.0\n  };\n  assert(round(area * 1000) == round(PI * 1000), \"guarded match on Circle\");\n\n  // ## Scalar match\n  // Match also works on integers, text, floats, booleans, and characters.\n  // Arms can be literals, ranges, `null`, or `_`.\n  grade = match 85 {\n    90..=100 => \"A\",\n    80..90   => \"B\",\n    _        => \"C\"\n  };\n  assert(grade == \"B\", \"range pattern 80..90 matches 85\");\n\n  // Or-patterns work on scalars too.\n  kind = match 2 {\n    1 | 2 | 3 => \"low\",\n    _         => \"high\"\n  };\n  assert(kind == \"low\", \"scalar or-pattern\");\n\n  // A `null` pattern matches when the value is absent (e.g. division by zero).\n  zero = 0;\n  check = match 1 / zero {\n    null => \"absent\",\n    _    => \"present\"\n  };\n  assert(check == \"absent\", \"null pattern matches div-by-zero\");\n\n  // Character literals work in match arms.\n  vowel = match 'e' {\n    'a' | 'e' | 'i' | 'o' | 'u' => true,\n    _ => false\n  };\n  assert(vowel, \"character or-pattern\");\n}",
          "sorted": "struct Elm {\n  key: text,\n  value: integer\n}\n\nstruct Db {\n  map: sorted < Elm[-key] >\n}\n\nfn main() {\n  // ## Adding Elements\n  // You initialise a sorted collection the same way as a vector.\n  // The elements are automatically placed in the right position as you add them.\n  db = Db {map: [\n  Elm {key: \"One\", value: 1 },\n  Elm {key: \"Two\", value: 2 },\n  Elm {key: \"Three\", value: 3 },\n  Elm {key: \"Four\", value: 4 }\n  ] };\n  // ## Looking Up by Key\n  // Use square brackets with the key value to find a record instantly.\n  // If the key is not present the result is null — you can check it with '!'.\n  assert(db.map[\"Two\"].value == 2, \"Key lookup: Two\");\n  assert(db.map[\"Three\"].value == 3, \"Key lookup: Three\");\n  assert(!db.map[\"Five\"], \"Missing key returns null\");\n  assert(!db.map[null], \"Null key returns null\");\n  // Append new elements with '+='; they are placed in the correct sorted position.\n  db.map +=[Elm {key: \"Zero\", value: 0 }];\n  assert(db.map[\"Zero\"].value == 0, \"Newly added element\");\n  // ## Iterating in Order\n  // A 'for' loop over a sorted collection visits elements in key order.\n  // Here the key is '-key' (descending text), so the order is: Zero, Two, Three, One, Four.\n  sum = 0;\n  for v in db.map {\n    sum = sum * 10 + v.value;\n  }\n  // Zero(0), Two(2), Three(3), One(1), Four(4) → 0*10+2=2, *10+3=23, *10+1=231, *10+4=2314\n  assert(sum == 2314, \"Sorted iteration total: {sum}\");\n  // ## Iterating in Reverse\n  // Wrap the collection in rev() to visit elements from last to first key order.\n  // Here the collection is sorted by '-key' (descending text), so the stored order is\n  // Zero, Two, Three, One, Four.  rev() visits them in the opposite order.\n  rev_sum = 0;\n  for v in rev(db.map) {\n    rev_sum = rev_sum * 10 + v.value;\n  }\n  // Four(4), One(1), Three(3), Two(2), Zero(0) → 4*10+1=41, *10+3=413, *10+2=4132, *10+0=41320\n  assert(rev_sum == 41320, \"Reverse iteration total: {rev_sum}\");\n  // ## Loop Helpers: #first, #count, and #remove\n  // 'v#first' is true for the very first element visited.\n  // 'v#count' is a running index starting at 0.\n  // 'v#remove' removes the current element while iterating.\n  first_key = \"\";\n  labels = \"\";\n  for v in db.map {\n    if v#first {\n      first_key = v.key\n    }\n    if !v#first {\n      labels += \",\"\n    }\n    labels += \"{v#count}:{v.key}\"\n  }\n  assert(first_key == \"Zero\", \"First element: {first_key}\");\n  assert(labels == \"0:Zero,1:Two,2:Three,3:One,4:Four\", \"Labels: {labels}\");\n  // Remove elements with value > 2 while iterating.\n  for v in db.map if v.value > 2 {\n    v#remove\n  }\n  sum2 = 0;\n  for v in db.map {\n    sum2 += v.value\n  }\n  // Remaining: Zero(0), Two(2), One(1) → sum = 3\n  assert(sum2 == 3, \"Sum after remove: {sum2}\");\n  // ## Removing by Key\n  // Assigning null to a sorted subscript removes the element with that key.\n  // Removing a key that is not present is a safe no-op.\n  db2 = Db {map: [\n  Elm {key: \"A\", value: 10 },\n  Elm {key: \"B\", value: 20 },\n  Elm {key: \"C\", value: 30 }\n  ] };\n  db2.map[\"B\"] = null;\n  assert(!db2.map[\"B\"], \"B was removed\");\n  assert(db2.map[\"A\"].value == 10, \"A still present\");\n  assert(db2.map[\"C\"].value == 30, \"C still present\");\n  db2.map[\"missing\"] = null;\n  // no-op; does not panic\n  sum3 = 0;\n  for v in db2.map {\n    sum3 += v.value\n  }\n  assert(sum3 == 40, \"Sum after key removal: {sum3}\");\n  // Note: #index is not available on sorted — use #count for a sequential counter.\n}\n\nstruct Word {\n  name: text,\n  score: integer\n}\n\nstruct Dict {\n  words: sorted<Word[name]>\n}\n\nfn main_ranges() {\n  // ## Iterating a Key Range\n  // Use an `if` guard inside a `for` loop to visit only records whose key falls\n  // within a range. Because the collection is sorted the guard still sees all\n  // elements, but the body only runs for the matching ones.\n  d = Dict { words: [\n    Word { name: \"apple\",      score: 5 },\n    Word { name: \"banana\",     score: 3 },\n    Word { name: \"cherry\",     score: 8 },\n    Word { name: \"date\",       score: 2 },\n    Word { name: \"elderberry\", score: 1 }\n  ] };\n  // Closed range: keys >= \"banana\" and <= \"date\".\n  range_total = 0;\n  for w in d.words if w.name >= \"banana\" && w.name <= \"date\" {\n    range_total += w.score\n  }\n  assert(range_total == 13, \"banana(3)+cherry(8)+date(2) = {range_total}\");\n  // ## Open-ended Range (tail)\n  // All records from \"cherry\" onward to the end of the sorted order.\n  tail_count = 0;\n  for w in d.words if w.name >= \"cherry\" {\n    tail_count += 1\n  }\n  assert(tail_count == 3, \"cherry, date, elderberry = {tail_count}\");\n  // ## Open-ended Range (head)\n  // All records up to and including \"banana\".\n  head_names = \"\";\n  for w in d.words if w.name <= \"banana\" {\n    head_names += w.name + \" \"\n  }\n  assert(head_names == \"apple banana \", \"apple and banana: '{head_names}'\");\n  // ## Range outside the for (building a result vector)\n  // Collect matching records into a vector for later use.\n  subset = [for w in d.words if w.name >= \"banana\" && w.name <= \"cherry\" { w.score }];\n  assert(subset[0] == 3, \"first in range: {subset[0]}\");\n  assert(subset[1] == 8, \"second in range: {subset[1]}\");\n}\n// filling and finding values",
          "index": "struct Elm {\n  nr: integer,\n  key: text,\n  value: integer\n}\n\nstruct Db {\n  map: index < Elm[nr, -key] >\n}\n\nfn main() {\n  // ## Adding and Looking Up Records\n  // Fill the index just like a vector. Elements are automatically kept in key order.\n  // This index is sorted first by 'nr' (ascending), then by 'key' (descending) for ties.\n  db = Db {map: [\n  Elm {nr: 101, key: \"One\", value: 1 },\n  Elm {nr: 92, key: \"Two\", value: 2 },\n  Elm {nr: 83, key: \"Three\", value: 3 },\n  Elm {nr: 83, key: \"Four\", value: 4 },\n  Elm {nr: 83, key: \"Five\", value: 5 },\n  Elm {nr: 63, key: \"Six\", value: 6 }\n  ] };\n  // Provide all key fields together inside brackets to find a record.\n  // Supply fewer fields to match all records that share a prefix.\n  assert(db.map[101, \"One\"].value == 1, \"Key lookup\");\n  assert(!db.map[12, \"\"], \"Missing key returns null\");\n  assert(!db.map[83, \"One\"], \"Wrong secondary key returns null\");\n  // ## Iterating in Order\n  // A 'for' loop visits all elements in key order.\n  total = 0;\n  for r in db.map {\n    total += r.value;\n  }\n  assert(total == 21, \"Sum of all values: {total}\");\n  // ## Range Queries\n  // Provide a range in the first key position to visit only the matching slice.\n  // '[83..92, \"Two\"]' means: nr from 83 up to (not including) 92, and key from \"Two\" down\n  // (since the key is sorted descending, \"Two\" is the start of that descending segment).\n  sum = 0;\n  for v in db.map[83..92, \"Two\"] {\n    sum = sum * 10 + v.value;\n  }\n  // Elements matched: (83, Three, 3), (83, Four, 4), (83, Five, 5)\n  assert(sum == 345, \"Range iteration result: {sum}\");\n  // ## Loop Helpers: #first and #count\n  // 'r#first' is true for the very first element visited.\n  // 'r#count' is a running counter starting at 0.\n  // Note: #index is not meaningful on index collections — use #count instead.\n  first_nr = 0;\n  count_total = 0;\n  for r in db.map {\n    if r#first {\n      first_nr = r.nr\n    }\n    count_total = r#count\n  }\n  assert(first_nr == 63, \"First element by key: {first_nr}\");\n  assert(count_total == 5, \"Total elements: {count_total}\");\n  // ## Removing by Key\n  // Assigning null to an index subscript removes the element with that exact key combination.\n  // Removing a key that is not present is a safe no-op.\n  db.map[92, \"Two\"] = null;\n  assert(!db.map[92, \"Two\"], \"element (92, Two) was removed\");\n  assert(db.map[101, \"One\"].value == 1, \"element (101, One) still present\");\n  db.map[999, \"Z\"] = null;\n  // no-op; does not panic\n  total2 = 0;\n  for r in db.map {\n    total2 += r.value\n  }\n  assert(total2 == 19, \"Sum after key removal: {total2}\");\n}",
          "hash": "struct Keyword {\n  name: text\n}\n\nstruct Data {\n  h: hash < Keyword[name] >\n}\n// ## Combining Hash and Vector\n// Pairing a hash with a vector on the same record type gives you the best of both worlds:\n// the hash for instant lookup by key, and the vector for iterating in insertion order.\n\nstruct Count {\n  t: text,\n  v: integer\n}\n\nstruct Counting {\n  entries: vector < Count >,\n  lookup: hash < Count[t] >\n}\n\nfn fill(c: Counting) {\n  c.entries =[\n {t: \"One\", v: 1 },\n {t: \"Two\", v: 2 },\n {t: \"Three\", v: 3 },\n {t: \"Four\", v: 4 }\n  ]\n}\n\nfn main() {\n  // ## Basic Lookup\n  // Fill a hash the same way you fill a vector. Look up by key with square brackets.\n  // A found record is truthy; a missing key returns null.\n  d = Data { };\n  d.h =[ {name: \"one\" }, {name: \"two\" }];\n  d.h +=[ {name: \"three\" }, {name: \"four\" }];\n  assert(d.h[\"three\"], \"Key exists\");\n  assert(!d.h[\"None\"], \"Missing key returns null\");\n  // ## Hash + Vector Together\n  // Here 'entries' is the vector (keeps insertion order) and 'lookup' is the hash (fast access).\n  // Both fields point to the same records — adding to one automatically updates the other.\n  c = Counting { };\n  fill(c);\n  assert(c.lookup[\"Three\"].v == 3, \"Hash lookup: Three\");\n  assert(c.lookup[\"One\"].v == 1, \"Hash lookup: One\");\n  assert(!c.lookup[\"Five\"], \"Missing key returns null\");\n  // Iterate in insertion order via the vector; look up by name via the hash.\n  // The vector also supports #first, #count, and #remove inside the loop.\n  add = 0;\n  for item in c.entries {\n    add += item.v;\n  }\n  assert(add == 10, \"Sum via vector iteration: {add}\");\n  // ## Removing a Key\n  // Assigning null to a hash subscript removes that element.\n  // Removing a key that is not present is a safe no-op.\n  d.h[\"three\"] = null;\n  assert(!d.h[\"three\"], \"three was removed\");\n  assert(d.h[\"one\"], \"one still present\");\n  d.h[\"missing\"] = null;\n  // no-op; does not panic\n  // ## Why you cannot iterate a hash directly\n  // A hash has no stable element order — internally, each record is placed in a slot\n  // chosen by a number computed from the key, so iteration order is unpredictable.\n  // 'for item in c.lookup' is therefore a compile error.\n  // Always pair a hash with a vector when you need both fast lookup and ordered iteration.\n}",
          "file": "fn cleanup() {\n  delete(\"test.bin\");\n  delete(\"test2.bin\");\n  delete(\"buffer.bin\");\n}\n\nstruct Buffer {\n  size: i32,\n  data: vector < single >\n}\n\nfn main() {\n  cleanup();\n  // Asking for the format of a directory path returns Directory, not a file\n  // format. `lines()` reads the named text file and splits it on newlines.\n  ex = file(\"tests/example\");\n  assert(ex#format == Directory, \"example is a directory\");\n  c = file(\"tests/example/config/terrain.txt\").lines();\n  assert(c[1] == \"    terrain = [\", \"Line was '{c[1]}'\");\n  // `exists` and `delete` are safe to call when the file is absent.\n  // `delete` returns false rather than crashing when nothing is there.\n  assert(!exists(\"test.bin\"), \"File should not exist before the test.\");\n  assert(!delete(\"nonexistent_xyz.bin\").ok(), \"delete on missing file not ok\");\n  // ## Writing a Text or Binary File\n  // Wrapping the file handle in a block ensures the file closes the moment\n  // the block ends. Set `f#format` to LittleEndian or BigEndian before\n  // writing binary data. Use `f += value` to append the raw bytes of any\n  // scalar value (u8, u16, i32, long, single, float, or text).\n {f = file(\"test.bin\");\n  assert(f#format == NotExists, \"File should not exist yet.\");\n  f#format = BigEndian;  // BigEndian: most-significant byte written first.\n  f += 0 as u8;\n  f += 1 as u8;\n  f += 0x203 as u16;\n  f += 0x4050607;\n  f += 0x8090a0b0c0d0e0fl;\n  // `f#size` returns the total number of bytes written so far.\n  assert(f#size == 16l, \"Should have written 16 bytes.\");\n  // Text is written as raw UTF-8 bytes with no length prefix.\n  f += \"Hello world!\";\n  assert(f#size == 28l, \"Size should be 28 bytes (16 + 12).\");\n }  // The file closes when the handle goes out of scope.\n  // `move(src, dst)` renames a file. It refuses if the destination already\n  // exists or if either path would leave the project directory.\n  assert(exists(\"test.bin\"), \"File should exist after writing.\");\n  assert(!move(\"test.bin\", \"../test.bin\").ok(), \"Should refuse to move outside the project.\");\n  assert(move(\"test.bin\", \"test2.bin\").ok(), \"Could not move the file.\");\n  // ## Reading Back What You Wrote\n  // When you open an existing file the default format is TextFile. Set\n  // `f#format` to match the format used when writing before you read any\n  // bytes. `f#read(n) as T` reads exactly n bytes and interprets them as\n  // type T. `f#index` is the byte offset where the last read started.\n  // `f#next` is the current read position; assign to it to seek anywhere.\n {f = file(\"test2.bin\");\n  assert(f#format == TextFile, \"The default format is TextFile.\");\n  f#format = LittleEndian;\n  // The file was written as BigEndian, so reading the same 4 bytes as\n  // LittleEndian produces a byte-swapped value — that is intentional here\n  // and confirms that the bytes were stored in the order you chose.\n  v = f#read(4) as i32;\n  assert(v == 0x3020100, \"BigEndian bytes 0..3 read as LittleEndian i32.\");\n  assert(f#index == 0l, \"Last read started at byte 0.\");\n  assert(f#next == 4l, \"Next read starts at byte 4.\");\n  // Seek to byte 16 to skip past the integers and read the text directly.\n  f#next = 16l;\n  s = f#read(5) as text;\n  assert(s == \"Hello\", \"Partial text read from offset 16.\");\n  assert(f#index == 16l, \"Last read started at byte 16.\");\n  assert(f#next == 21l, \"Next position after 5-byte text read.\");\n  // Requesting more bytes than remain simply returns whatever is left.\n  rest = f#read(100) as text;\n  assert(rest == \" world!\", \"Read continues to end of file.\");\n  assert(f#next == f#size, \"Position should be at end of file.\");\n  // You can seek back to any position and re-read.\n  f#next = 0l;\n  assert(f#read(4) as i32 == 0x3020100, \"Seek-and-reread matches original.\");\n }\n  assert(delete(\"test2.bin\").ok(), \"Could not remove the test file.\");\n  // ## Working with Vectors and Struct Data\n  // `f += vector<T>` writes every element in sequence as raw bytes, which is\n  // the fastest way to dump a whole collection to disk. Setting `f#size = n`\n  // truncates or zero-extends the file to exactly n bytes — useful for\n  // discarding the tail after you have finished writing.\n {f = file(\"buffer.bin\");\n  f#format = LittleEndian;\n  ints =[1, 2, 3, 4];\n  f += ints;\n  assert(f#size == 16l, \"Four i32 values = 16 bytes\");\n  // Truncate to the first two integers.\n  f#size = 8l;\n  assert(f#size == 8l, \"Truncated to 8 bytes\");\n }\n  assert(delete(\"buffer.bin\").ok(), \"Could not remove buffer.bin after vector write test.\");\n  // Write a count followed by individual float values. `sizeof(T)` returns\n  // the byte width of a type, so you can compute the correct read length\n  // without hard-coding magic numbers.\n {buf = file(\"buffer.bin\");\n  buf#format = LittleEndian;\n  buf += 4 as i32;\n  buf += 1.1f;\n  buf += 1.2f;\n  buf += 2.1f;\n  buf += 2.2f;\n }\n  // Read the count, then use it to read exactly that many floats directly\n  // into a struct field. This pattern lets you serialise and deserialise\n  // structs with variable-length data cleanly.\n {b = Buffer { };\n  f = file(\"buffer.bin\");\n  f#format = LittleEndian;\n  n = f#read(4) as i32;\n  b.data = f#read(n * sizeof(single));\n }\n  assert(delete(\"buffer.bin\").ok(), \"Could not remove buffer.bin.\");\n\n  // ## Error handling\n  // File operations that can fail return a `FileResult` enum.\n  // Call `.ok()` to check success. The program does not crash on failure —\n  // you decide what to do.\n  result = delete(\"this_file_does_not_exist.txt\");\n  assert(!result.ok(), \"delete missing file returns not-ok\");\n\n  // Reading a non-existent file produces an empty result, not a crash.\n  ghost = file(\"no_such_file.txt\");\n  assert(ghost#format == NotExists, \"non-existent file has NotExists format\");\n\n  // `move` refuses paths outside the project directory.\n  assert(!move(\"any.txt\", \"../escape.txt\").ok(), \"move outside project fails\");\n\n  // Writing to a read-only or invalid path also returns a FileResult.\n  // Always check `.ok()` after `delete`, `move`, `mkdir`, and `mkdir_all`.\n}",
          "lexer": "use lexer;\nfn main() {\n  l = lexer::Lexer { };\n  l.set_tokens([\"+=\", \"*=\", \"-=\", \"<=\", \">=\", \"!=\", \"==\", \">>\", \"<<\", \"->\", \"=>\", \">>>\", \"..\", \"..=\", \"&&\", \"||\"]);\n  l.set_keywords([\"for\", \"in\", \"if\", \"else\", \"fn\", \"pub\", \"use\", \"struct\", \"enum\", \"match\", \"and\", \"or\"]);\n  // ## Reading Tokens\n  // `parse_string(name, source)` feeds source text into the lexer. The name\n  // is used in error messages and position reports. After that, call the\n  // typed reader functions one by one to consume tokens in order.\n  //\n  // `int()` consumes and returns the next integer token, or null if the\n  // current token is not an integer. `long_int()` does the same for integers\n  // suffixed with `l`. `matches(s)` consumes the next token only when it\n  // equals s and returns true; otherwise it leaves the token in place and\n  // returns false. `peek()` returns the next token as text without consuming\n  // it. `position()` returns the current location as `file:line:col`.\n  l.parse_string(\"Tokens\", \"12 += -2 * 3l >> 4\");\n  assert(l.int() == 12, \"Integer\");\n  assert(!l.matches(\"+\"), \"Incorrect plus\");\n  assert(l.peek() != \"+\", \"Incorrect plus\");\n  assert(l.matches(\"+=\"), \"Incorrect plus_is\");\n  assert(l.int() == -2, \"Second integer\");\n  assert(l.matches(\"*\"), \"Incorrect multiply\");\n  assert(l.int() != 3, \"Third number\");\n  assert(l.long_int() == 3, \"Incorrect long\");\n  assert(l.position() == \"Tokens:1:15\", \"Incorrect position {l.position()}\");\n  assert(!l.matches(\">\"), \"Incorrect higher\");\n  assert(l.matches(\">>\"), \"Incorrect logical shift\");\n  assert(l.position() == \"Tokens:1:18\", \"Incorrect position {l.position()}\");\n  // ## String Literals and Comments\n  // `constant_text()` reads a double-quoted string and handles special codes\n  // like \\n (newline) and \\\\ (backslash). `constant_character()` reads a\n  // single-quoted character literal and returns it as text.\n  l.parse_string(\"Texts\", \"\\\"123\\\" + '4'\");\n  assert(l.constant_text() == \"123\", \"Incorrect text literal\");\n  assert(l.matches(\"+\"), \"Incorrect add\");\n  assert(l.constant_character() == \"123\", \"Incorrect text literal\");\n  // The lexer collects `//` comments automatically as it scans. You do not\n  // need to handle them yourself. `last_comment()` returns the accumulated\n  // comment text since the last consumed token. When multiple comment lines\n  // appear in a row they are joined with newlines into a single string.\n  // `comment_behind()` is true when the comment appeared on the same line as\n  // the preceding token rather than on its own line above. `is_finished()`\n  // returns true once every token has been consumed.\n  l.parse_string(\"Comments\", \"// starting comments\\n123 // same line comment\\n// extra comment\\n4\");\n  assert(!l.comment_behind(), \"Initial comment not behind\");\n  assert(l.last_comment() == \"starting comments\", \"Initial comment\");\n  assert(l.int() == 123, \"Content integer\");\n  assert(l.comment_behind(), \"Second comment is behind\");\n  assert(l.last_comment() == \"same line comment\\nextra comment\", \"Second comment\");\n  assert(!l.is_finished(), \"Not Ready\");\n  assert(l.int() == 4, \"Second integer\");\n  assert(l.last_comment() == \"\", \"No remaining comment\");\n  assert(l.is_finished(), \"Ready\");\n  // ## Embedded Format Expressions\n  // Loft string literals can embed expressions with `{expr}`. The lexer\n  // exposes a protocol that lets you parse these yourself. When\n  // `constant_text()` reaches a `{`, it returns the literal text before it\n  // and sets `is_formatting()` to true. At that point call\n  // `set_formatting(false)` and parse the embedded expression normally using\n  // the usual token readers. When the expression is done, call\n  // `set_formatting(true)` and consume the closing `}}`. Then\n  // `constant_text()` continues with the next segment of the string.\n  l.parse_string(\"Formatting\", \"\\\"abc{{12 + 34}}def\\\"\");\n  assert(l.constant_text() == \"abc\", \"Before formatting\");\n  assert(l.is_formatting(), \"Formatting\");\n  l.set_formatting(false);\n  assert(l.int() == 12, \"First integer\");\n  assert(l.matches(\"+\"), \"Incorrect plus\");\n  assert(l.int() == 34, \"Second integer\");\n  l.set_formatting(true);\n  assert(l.matches(\"}}\"), \"Incorrect closing brace\");\n  assert(l.constant_text() == \"def\", \"After formatting\");\n  assert(!l.is_formatting(), \"Formatting\");\n}",
          "parser": "use parser;\nfn main() {\n  // ## Parsing a minimal function\n  // The double braces '{{' and '}}' produce literal '{' and '}' inside a\n  // Loft format string — needed here because the source code itself contains braces.\n  parser::parse(\"hello\", \"fn main() {{ println(\\\"Hello World\\\"); }}\");\n  // ## Parsing a struct and function together\n  // The parser validates the entire source snippet as one unit.\n  // Both the struct definition and the function body are checked.\n  parser::parse(\"point\", \"struct Point {{ x: integer, y: integer }} fn origin() -> Point {{ Point {{ x: 0, y: 0 }} }}\");\n  // ## Parsing an enum\n  // Both a plain variant and a struct variant (with fields) are recognised.\n  parser::parse(\"shape\", \"enum Shape {{ Circle {{ radius: float }}, Rectangle {{ w: float, h: float }} }}\");\n  // ## Parsing a for loop and arithmetic\n  // This exercises the expression parser and range syntax.\n  parser::parse(\"loop\", \"fn sum(n: integer) -> integer {{ t = 0; for i in 1..=n {{ t += i; }} t }}\");\n  // ## Practical use: validating user-supplied code\n  //\n  // If your application lets users write Loft snippets (for scripting or\n  // configuration), you can parse them before executing:\n  //\n  //   snippet = read_user_input();\n  //   parser::parse(\"user_code\", snippet);\n  //   // If parse() emits errors, the snippet was invalid — show them to the user.\n  //\n  // Combine this with the lexer (see the Lexer page) when you need to extract\n  // individual tokens from the source rather than validate all of the syntax.\n  println(\"parser test passed\");\n}",
          "libraries": "use testlib;\n// ## Constants and Enums\n// Library constants and enum variants are accessed with the `libname::`\n// prefix. You can compare, order, and convert enum values exactly as you\n// would with enums defined in the same file.\n// ## Struct Construction and Field Access\n// Construct a library struct with its full namespace prefix. Omitting the\n// prefix is a parse error. Once you have a value, field access uses the plain\n// dot notation with no prefix needed.\n// ## Calling Library Methods\n// Methods defined in the library are called on the value directly — no prefix\n// on the call site. Free functions (not methods) do need the `libname::` prefix.\n// ## Extending a Library Type\n// You can add new methods to a library type from your own file. Write the\n// `self` parameter type with the `::` separator and the compiler treats the\n// function as a method on that type.\nfn shifted(self: testlib::Point, dx: float, dy: float) -> testlib::Point {\n  testlib::Point {x: self.x + dx, y: self.y + dy }\n}\n\nfn main() {\n  // Constants from a library require the library prefix.\n  assert(testlib::MAX_SIZE == 100, \"library constant MAX_SIZE\");\n  assert(testlib::MIN_SIZE == 1, \"library constant MIN_SIZE\");\n  // Library enum variants: comparison and ordering work as normal.\n  s = testlib::Ok;\n  assert(s == testlib::Ok, \"enum equality\");\n  assert(s < testlib::Error, \"enum ordering\");\n  assert(\"{s}\" == \"Ok\", \"enum to text: {s}\");\n  assert(\"Warning\" as testlib::Status == testlib::Warning, \"text to enum\");\n  // Library enum values can be passed to library free functions.\n  assert(testlib::status_text(testlib::Error) == \"err\", \"free fn with enum arg\");\n  // Structs are constructed with namespace prefix and accessed by field.\n  p = testlib::Point {x: 3.0, y: 4.0 };\n  assert(p.x == 3.0, \"field access: x={p.x}\");\n  assert(p.y == 4.0, \"field access: y={p.y}\");\n  // Methods defined in the library are called without a prefix.\n  dist = p.distance();\n  assert(round(dist) == 5.0, \"method call: distance={dist}\");\n  // User-defined method on a library type (self: testlib::Point) works.\n  assert(p.shifted(1.0, 2.0).x == 4.0, \"shifted x\");\n  assert(p.shifted(0.0, 2.0).y == 6.0, \"shifted y\");\n  // Scalar fields can be mutated directly.\n  b = testlib::Bag {label: \"test\", count: 0 };\n  b.label = \"updated\";\n  assert(b.label == \"updated\", \"direct scalar field mutation\");\n  // Methods that mutate scalar fields work.\n  b.bump();\n  assert(b.count == 1, \"method scalar mutation: count={b.count}\");\n  b.bump();\n  assert(b.count == 2, \"method scalar mutation: count={b.count}\");\n  // Free functions: called with the library prefix.\n  assert(testlib::add(3, 4) == 7, \"free function add\");\n  assert(testlib::add(0, -5) == -5, \"free function negative\");\n  // Library types work as function parameter types when written with their\n  // full namespace prefix in the function signature.\n  // A struct with a vector field can be initialised via a struct literal,\n  // including elements that are themselves library structs.\n  bag2 = testlib::Bag {label: \"full\", count: 3, items: [\n  testlib::Point {x: 1.0, y: 0.0 },\n  testlib::Point {x: 0.0, y: 1.0 }\n  ] };\n  assert(len(bag2.items) == 2, \"initialized vector field: {len(bag2.items)}\");\n  assert(bag2.items[0].x == 1.0, \"vector field element access\");\n  // Appending a struct variable with `+= [var]` and a whole vector with `+= vec` both work.\n  extra = testlib::Point {x: 7.0, y: 8.0 };\n  bag2.items +=[extra];\n  assert(len(bag2.items) == 3, \"append via var: len={len(bag2.items)}\");\n  assert(bag2.items[2].x == 7.0, \"append via var: x={bag2.items[2].x}\");\n  more_pts =[testlib::Point {x: 9.0, y: 10.0 }, testlib::Point {x: 11.0, y: 12.0 }];\n  bag2.items += more_pts;\n  assert(len(bag2.items) == 5, \"append vector: len={len(bag2.items)}\");\n  assert(bag2.items[3].x == 9.0, \"append vector[3].x={bag2.items[3].x}\");\n  // Importing the same library twice is silently ignored. A library can\n  // itself import other libraries using `use`, so dependency chains work.\n  // ## Package Layout and loft.toml\n  //\n  // A library can be distributed as a directory package instead of a single\n  // flat file. The packaged directory layout is:\n  //\n  //   mylib/\n  //     loft.toml           optional manifest\n  //     src/\n  //       mylib.loft        library source (default entry)\n  //\n  // When the interpreter searches a lib directory and finds `<dir>/mylib/`\n  // it looks for `<dir>/mylib/src/mylib.loft` automatically.\n  //\n  // The optional `loft.toml` manifest supports two settings:\n  //\n  //   [package]\n  //   loft = \">=1.0\"        minimum interpreter version required\n  //\n  //   [library]\n  //   entry = \"src/mylib.loft\"   override the default entry path\n  //\n  // If the interpreter version is below the stated minimum, loading the\n  // library produces a fatal compile error describing the version mismatch.\n  // If no manifest is present, the default entry `src/<name>.loft` is used.\n  // ## Wildcard and Selective Imports\n  // By default, library names require the `libname::` prefix. You can\n  // import names directly into your namespace with `use lib::*` (wildcard)\n  // or `use lib::Name, Other` (selective). Only `pub`-marked definitions\n  // in the library are imported this way. Non-pub definitions remain\n  // accessible via the `lib::name` prefix.\n  // ## Limitations\n  //\n  // **`use` must appear before all definitions.** If you write a function\n  // first and then a `use`, the compiler reports a syntax error.\n  //\n  // **`pub` controls import visibility.** Only `pub`-marked definitions\n  // are available via wildcard (`use lib::*`) or selective import.\n  // Non-pub definitions are still accessible with the `lib::name` prefix.\n  //\n  // **No native extension loading.** Libraries are pure `.loft` files.\n  // Native Rust extensions (`loft.toml` with `native = \"...\"`) are planned\n  // for a future release.\n}",
          "store_locks": "struct Counter {\n  value: integer\n}\n// ## const parameters\n// 'const' on a parameter is a compile-time promise: \"this function will not\n// modify this value.\" The compiler enforces it — any assignment to a const\n// parameter is a compile error, caught before you run anything.\n\nfn read_value(self: const Counter) -> integer {\n  self.value\n}\n// A non-const parameter leaves the store unlocked so the function can write.\n\nfn increment(self: Counter) {\n  self.value += 1\n}\n\nfn main() {\n  // ## const local variables\n  // Declare a local variable with 'const' to signal that it will not change\n  // after its first assignment. The compiler rejects any later assignment to\n  // it — reassigning or appending to a const variable is a compile error.\n  //\n  // This is handy for configuration values or lookup tables that should never\n  // be overwritten by accident deep inside a long function.\n  const limit = 100;\n  assert(limit == 100, \"const integer is readable\");\n  // const also works for struct references.\n  const cfg = Counter {value: 42 };\n  assert(cfg.value == 42, \"const reference is readable\");\n  // Passing a const reference to a const parameter is always allowed.\n  assert(read_value(cfg) == 42, \"const passed to const param\");\n  // ## Calling methods on const references\n  // A non-const method can still be called on a non-const variable even\n  // after you have manually locked the store; the lock is a runtime check.\n  c = Counter {value: 10 };\n  increment(c);\n  assert(c.value == 11, \"increment modified c\");\n  // ## Runtime store locks with #lock\n  // '#lock' is an attribute on any reference variable.\n  // Setting it to true turns on a runtime guard: any write to that store\n  // will panic immediately, wherever it happens.\n  // A freshly created reference starts unlocked.\n  d = Counter {value: 5 };\n  assert(!d#lock, \"new store starts unlocked\");\n  d#lock = true;\n  assert(d#lock, \"store is locked after assignment\");\n  // You can still read from a locked store — only writes are blocked.\n  assert(read_value(d) == 5, \"locked store is still readable\");\n  // ## When to use each approach\n  // * Use 'const' on parameters and locals to express your design intent\n  //   and get compile-time safety at zero cost.\n  // * Use '#lock = true' when you want a runtime tripwire: you suspect some\n  //   code path is mutating a value it should not touch, and you want the\n  //   program to panic with a precise location rather than corrupt silently.\n  // get_store_lock() is the function form of the #lock attribute.\n  // Both return the same boolean.\n  e = Counter {value: 99 };\n  assert(get_store_lock(e) == e#lock, \"function form matches attribute before lock\");\n  e#lock = true;\n  assert(get_store_lock(e) == e#lock, \"function form matches attribute after lock\");\n}",
          "parallel_execution": "struct Score {\n  value: integer\n}\n\nstruct ScoreList {\n  items: vector < Score >\n}\n\nstruct DoubledScore {\n  label: text,\n  doubled: integer\n}\n\nfn double_score(thr_r: const Score) -> integer {\n  thr_r.value * 2\n}\n\nfn scale_score(thr_r: const Score, thr_factor: integer) -> integer {\n  thr_r.value * thr_factor\n}\n\nfn make_doubled(thr_r: const Score) -> DoubledScore {\n  DoubledScore { label: \"v{thr_r.value}\", doubled: thr_r.value * 2 }\n}\n\nfn get_value(self: const Score) -> integer {\n  self.value\n}\n\nfn make_scores() -> ScoreList {\n  thr_q = ScoreList { };\n  thr_q.items +=[Score {value: 10 }, Score {value: 20 }, Score {value: 30 }];\n  thr_q\n}\n\nfn main() {\n  // ## Global Function (Form 1)\n  // Each Score's value is doubled by `double_score` across 4 threads.\n  // The loop body sees `b` with the doubled value, in original order.\n  q = make_scores();\n  sum = 0;\n  for thr_a in q.items par(thr_b = double_score(thr_a), 4) {\n    sum += thr_b;\n  }\n  // 10*2 + 20*2 + 30*2 = 120\n  assert(sum == 120, \"parallel double: sum == 120\");\n\n  // ## Extra Arguments\n  // The worker function can take extra arguments from the calling scope.\n  // Here `scale_score(a, factor)` passes `factor=3` to every worker.\n  q1b = make_scores();\n  factor = 3;\n  scaled_sum = 0;\n  for thr_a in q1b.items par(thr_b = scale_score(thr_a, factor), 4) {\n    scaled_sum += thr_b;\n  }\n  // 10*3 + 20*3 + 30*3 = 180\n  assert(scaled_sum == 180, \"extra arg: scaled sum == 180\");\n\n  // ## Struct Return\n  // Workers can return a struct.  Text fields are deep-copied so they\n  // remain valid after the worker thread exits.\n  q2 = make_scores();\n  labels = \"\";\n  for thr_sa in q2.items par(thr_ds = make_doubled(thr_sa), 1) {\n    labels += \"{thr_ds.label},\";\n  }\n  assert(labels == \"v10,v20,v30,\", \"struct return: {labels}\");\n\n  // ## Method Call (Form 2)\n  // `b=a.get_value()` dispatches the method on each element in parallel.\n  // This is syntactic sugar — equivalent to `b=get_value(a)`.\n  q3 = make_scores();\n  total = 0;\n  for thr_a in q3.items par(thr_b = thr_a.get_value(), 4) {\n    total += thr_b;\n  }\n  assert(total == 60, \"method call: total == 60\");\n\n  // ## Empty Vector\n  // An empty vector is safe — the loop body never executes,\n  // no threads are spawned.\n  empty = ScoreList { };\n  thr_n = 0;\n  for thr_a in empty.items par(thr_b = double_score(thr_a), 1) {\n    thr_n += 1;\n  }\n  assert(thr_n == 0, \"empty: 0 iterations\");\n\n  // ## Sequential fallback\n  // Using `par(..., 1)` runs the worker on a single thread — useful\n  // for debugging.  The behaviour is identical; only the parallelism changes.\n  q4 = make_scores();\n  seq_sum = 0;\n  for thr_a in q4.items par(thr_b = double_score(thr_a), 1) {\n    seq_sum += thr_b;\n  }\n  assert(seq_sum == 120, \"sequential par(1): same result\");\n}",
          "logging": "fn main() {\n  // Without a log.conf these calls do nothing — the tests below pass\n  // even though no output is produced.\n  log_info(\"starting up\");\n  log_warn(\"this is a warning\");\n  log_error(\"something went wrong\");\n  log_fatal(\"critical failure\");\n  // ## Example log.txt output\n  //\n  // When a 'log.conf' is present with 'level = info', the four calls above\n  // produce entries like this in 'log.txt':\n  //\n  //   2026-03-24 09:15:00 INFO   app.loft:3  starting up\n  //   2026-03-24 09:15:00 WARN   app.loft:4  this is a warning\n  //   2026-03-24 09:15:00 ERROR  app.loft:5  something went wrong\n  //   2026-03-24 09:15:00 FATAL  app.loft:6  critical failure\n  //\n  // Each line contains: timestamp, severity level, source file and line\n  // number, then the message. This makes it easy to search the file for\n  // errors or trace back to the exact line that produced a message.\n  // A true assert never logs anything — it is only the false case that logs.\n  assert(true, \"this should never fail\");\n  // ## Typical usage pattern\n  //\n  // In a real program you would write something like:\n  //\n  //   fn process(item: Item) {\n  //       log_info(\"processing item {item.id}\");\n  //       result = do_work(item);\n  //       if !result {\n  //           log_error(\"work failed for item {item.id}\");\n  //           return;\n  //       }\n  //       log_info(\"finished item {item.id} successfully\");\n  //   }\n  //\n  // The log messages give you a record of exactly what the program did and\n  // where it went wrong, without cluttering the terminal during normal runs.\n  println(\"logging test passed\");\n}",
          "time": "fn main() {\n  // ## Wall-clock time: now()\n  // 'now()' returns the current time as milliseconds since 1970-01-01T00:00:00 UTC.\n  // The value is always positive and grows over time.\n  t = now();\n  assert(t > 0l, \"now() must be positive\");\n  // Two successive calls return non-decreasing values.\n  t2 = now();\n  assert(t2 >= t, \"now() must be non-decreasing\");\n  // ## Elapsed time: ticks()\n  // 'ticks()' measures microseconds since the program started.\n  // It uses a monotonic clock so it never jumps backward.\n  start = ticks();\n  assert(start >= 0l, \"ticks() must be non-negative\");\n  end = ticks();\n  assert(end >= start, \"ticks() must be monotonically non-decreasing\");\n  // ## Measuring elapsed time\n  // Subtract two 'ticks()' values to get the duration in microseconds.\n  // Divide by 1000 to convert to milliseconds.\n  //\n  //   elapsed_us  = end_ticks - start_ticks\n  //   elapsed_ms  = elapsed_us / 1000l\n  //\n  // Example: measure how long a loop takes.\n  t_before = ticks();\n  sum = 0;\n  for i in 0..1000 {\n    sum += i\n  }\n  t_after = ticks();\n  elapsed = t_after - t_before;\n  assert(elapsed >= 0l, \"elapsed time must be non-negative: {elapsed}\");\n  assert(sum == 499500, \"loop produced wrong sum: {sum}\");\n  // ## Common patterns\n  //\n  // Timestamp a log entry (seconds since epoch):\n  //   seconds = now() / 1000l\n  //\n  // Seed the random number generator with the current time:\n  //   rand_seed(now() as integer)\n  //\n  // Simple stopwatch:\n  //   start = ticks()\n  //   ... do work ...\n  //   log_info(\"Done in {(ticks() - start) / 1000l} ms\")\n}",
          "safety": "fn counted_call(calls: &integer, value: integer) -> integer {\n  calls += 1;\n  value\n}\n\n// Used to obtain a null text value (an uninitialized field is the NUL sentinel).\nstruct NullTextHolder { s: text }\n\nfn main() {\n  // ## Null values — hidden reserved values\n  // Every type reserves one special value to mean \"nothing here\" (null).\n  // That reserved value looks like any other value, so be aware of what it\n  // is for each type:\n  // - `boolean`         — `false` is the null value\n  // - `integer`         — the most negative 32-bit integer (-2 147 483 648) is null\n  // - `long`            — the most negative 64-bit integer is null\n  // - `float`/`single`  — `NaN` (Not a Number) is null\n  // - `character`       — the NUL character (code point 0) is null\n  // - `text`            — a single NUL character (`'\\0'`) is null; the empty string `\"\"` is NOT null\n  // - `reference`       — record 0 is null\n  // - plain `enum`      — byte value 255 is null (limits enums to 255 variants)\n  //\n  // This means there is one value per type that you cannot distinguish from\n  // null. For integers, that is -2 147 483 648. Division by zero also\n  // produces this same value, so both paths look the same to your code:\n  zero = 0;\n  n = 1 / zero;\n  assert(!n, \"div-by-zero is null\");\n  assert(n != 0, \"null is not zero; it is -2 147 483 648\");\n  assert(n < 0, \"i32::MIN is the most negative 32-bit integer\");\n  // Arithmetic on null propagates: null plus anything is null.\n  assert(!(n + 1), \"null + 1 is still null\");\n  // Text null is the NUL character ('\\0'), not the empty string.\n  // Parsing a JSON object with a missing text field produces the NUL sentinel:\n  holder = NullTextHolder.parse(`{{}}`);\n  assert(!holder.s, \"missing JSON text field is null (the NUL sentinel)\");\n  empty = \"\";\n  assert(empty, \"empty string is NOT null — this surprises most newcomers\");\n  // Mitigation: Use `long` when you need the full 32-bit integer range, or\n  // declare struct fields as `not null` so that reserved value can be used as data.\n\n  // ## Integer overflow wraps silently\n  // 32-bit integers wrap when they exceed roughly 2 billion. There is no\n  // runtime overflow check and no exception. The result is a small or\n  // negative number and the program continues as if nothing happened.\n  // The following would wrap silently in a release build:\n  //   big = 2000000000; big + big  →  negative number\n  // Mitigation: Use `long` (64-bit) when multiplying or summing large\n  // values: `big as long + big as long` avoids the wrap.\n  // Design: a future `--debug` flag will turn silent overflow into a logged\n  // WARN with file:line context so overflows are visible during development\n  // without affecting release performance.\n  big = 2000000000;\n  assert(big as long + big as long == 4000000000l, \"long avoids wrap\");\n\n  // ## Bitwise operators with zero\n  // All bitwise operators (AND, OR, XOR, shift) work correctly with zero.\n  // Zero is the identity element for OR, XOR, and shift; zero for AND.\n  assert(0b1010 & 0 == 0, \"AND with 0: zero\");\n  assert(0b1010 | 0 == 0b1010, \"OR with 0: identity\");\n  assert(0b1010 ^ 0 == 0b1010, \"XOR with 0: identity\");\n  assert(5 << 0 == 5, \"shift left by 0: identity\");\n  assert(5 >> 0 == 5, \"shift right by 0: identity\");\n\n  // ## Float null is NaN\n  // Floats represent null as `NaN` (Not a Number). Null floats behave\n  // consistently with other null types: null is not equal to anything\n  // (including itself), and null is not-equal to everything.\n  bad = 0.0 / 0.0;\n  assert(!bad, \"NaN is falsy — this is how you detect null floats\");\n  assert(!(bad == bad), \"null == null is false\");\n  assert(bad != bad, \"null != null is true\");\n  assert(bad != 0.0, \"null != 0.0 is true\");\n  // Use `!f` or `f ?? default` to check for null floats.\n\n  // ## Text length counts bytes, not characters\n  // `len()` on text returns the number of UTF-8 bytes, not the number of\n  // visible characters. Multi-byte characters (accented letters, emoji,\n  // CJK) each occupy 2-4 bytes.\n  // `size()` returns the number of Unicode code points (characters).\n  // These two values differ whenever the text contains any multi-byte character.\n  emoji = \"Hi 😊!\";\n  assert(len(emoji) == 8, \"5 visible chars but 8 bytes (emoji is 4 bytes)\");\n  assert(size(emoji) == 5, \"size() counts code points: {size(emoji)}\");\n  // Slicing and indexing also use byte offsets. Slicing in the middle of a\n  // multi-byte character is an error.\n  // Mitigation: Use `for c in text` to iterate by character. Use\n  // `c#index` and `c#next` to get the byte boundaries of each character.\n  count = 0;\n  for c in emoji { count += 1; }\n  assert(count == 5, \"for-loop iterates by character, not byte\");\n\n  // ## `#index` means different things on text and vectors\n  // On a text loop, `c#index` is the byte offset of the current character.\n  // On a vector loop, `v#index` is the 0-based element position.\n  // Both are called `#index` but represent different units.\n  v = [10, 20, 30];\n  idx = 0;\n  for x in v { idx = x#index; }\n  assert(idx == 2, \"vector #index: element position (0-based)\");\n  // Text #index is a byte offset, not a character count:\n  t = \"aé\";\n  byte_pos = 0;\n  for c in t { byte_pos = c#index; }\n  assert(byte_pos == 1, \"text #index: byte offset of 'é' (byte 1, not char 1)\");\n\n  // ## `??` evaluates the left side exactly once\n  // The `??` operator means \"use this value, or if it is null, use the right side instead\".\n  // The left-hand expression is evaluated exactly once regardless of whether the result is\n  // null. The example below uses `counted_call` (defined above) to verify this.\n  calls = 0;\n  qq_result = counted_call(calls, 7) ?? 99;\n  assert(calls == 1, \"?? evaluated left side exactly once: {calls}\");\n  assert(qq_result == 7, \"result is the value from that single evaluation: {qq_result}\");\n  // This means `result = expensive_call() ?? default` is safe: the function\n  // is called once. If it returns null, `default` is used. There is no double call.\n\n  // ## Text indexing and slicing return different types\n  // `txt[i]` returns a `character` (a single Unicode scalar value).\n  // `txt[i..j]` returns `text` (a UTF-8 string). These are different types.\n  txt = \"hello\";\n  ch = txt[0];\n  slice = txt[0..1];\n  assert(ch == 'h', \"indexing returns a character\");\n  assert(slice == \"h\", \"slicing returns text\");\n  // Building text from characters requires format interpolation:\n  result = \"\";\n  for c in \"abc\" { result += \"{c}\"; }\n  assert(result == \"abc\", \"characters must be formatted into text\");\n\n  // ## Format strings: braces are always interpreted\n  // Every string literal in loft is a format string. Literal braces must\n  // be escaped as `{{` and `}}`:\n  n = 42;\n  assert(\"{n}\" == \"42\", \"single braces: format expression\");\n  assert(len(\"{{}}\") == 2, \"double braces produce literal brace chars\");\n  // Forgetting to escape braces in expected output is a common mistake in\n  // assertions and comparisons.\n\n  // ## Hash collections cannot be iterated\n  // Hashes are lookup structures, not ordered collections. You cannot write\n  // `for item in my_hash { }`. If you need both fast lookup and ordered\n  // iteration, keep a vector and a hash pointing at the same record type.\n  // See the Hash documentation page for the recommended pattern.\n\n  // ## Mutation guard blocks appending during iteration\n  // The compiler prevents `v += [x]` inside `for e in v`. This protects\n  // against infinite loops. The guard also catches field access:\n  // `for e in db.items { db.items += [x]; }` is blocked too.\n  // The only allowed mutation is `e#remove` inside a filtered loop.\n\n  // ## If-expression requires else when used as a value\n  // Using `if` as a value expression without an `else` clause is a compile\n  // error. This prevents accidental null values from missing branches.\n  // If-statements (where the body has no value) do not need else.\n  // For example, `x = if cond { 1 }` is an error; write `x = if cond { 1 } else { 0 }`.\n\n  // ## Match guards do not prove a variant is handled\n  // A guarded arm like `Red if cond => ...` does not count as handling\n  // the `Red` variant because the guard can fail at runtime. Even if\n  // every variant has a guarded arm, you still need a wildcard `_` or an\n  // unguarded arm so the compiler knows every case is covered.\n\n  // ## Ref-parameter semantics\n  // Without `&`, appending to a vector parameter is local — the caller's\n  // vector does not grow. With `&`, the caller sees the new elements.\n  // Field-level mutations (e.g. `v[i].field = x`) are always visible to the\n  // caller because both sides share the same underlying database reference.\n  // Rule of thumb: Use `&vector<T>` when the function needs to grow the\n  // vector. Use plain `vector<T>` when the function only reads or modifies\n  // existing elements.\n\n  // ## File I/O assumes UTF-8\n  // All file reading in loft assumes the file content is valid UTF-8. Reading\n  // a binary file or a file in a different encoding (e.g. Latin-1) will crash\n  // the program at runtime. There is currently no way to read raw bytes.\n  // Mitigation: Only read files you know to be UTF-8. If you need to process\n  // binary data, convert it to UTF-8 externally before passing it to loft.\n\n  // ## XOR is `^`, not exponentiation\n  // Unlike some languages where `^` means \"power\", in loft `^` is bitwise\n  // XOR. The `**` operator (Python/Ruby exponentiation) does not exist either.\n  // Use the `pow()` function for exponentiation.\n  assert((0b1010 ^ 0b1100) == 0b0110, \"^ is XOR\");\n  assert(pow(2.0, 3.0) == 8.0, \"use pow() for power\");\n}",
          "json": "struct User {\n  id: integer,\n  name: text,\n  email: text\n}\n\n// ## Parsing — JSON to struct\n// Call 'Type.parse(text)' to create a struct from JSON text.\n// Both JSON-style quoted field names (\"name\": value) and loft-style unquoted\n// field names (name: value) are accepted.  Missing fields get null sentinels.\n// Extra fields in the input are silently skipped.\n//\n//   user = User.parse(json_text)\n//\n// ## Vectors\n// Parse a JSON array into a vector of structs with 'vector<T>.parse(text)'.\n//\n//   scores = vector<Score>.parse(\"[{\\\"v\\\":1},{\\\"v\\\":2}]\")\n//\nstruct Score {\n  value: integer\n}\n\n// ## Parse Errors\n// After parsing, check '#errors' on the result to see what went wrong.\n// Each error is a text string describing the problem and its location.\n//\n//   data = MyType.parse(bad_json)\n//   for e in data#errors { log_warn(e) }\n//\n// ## Nested Structs\n// Structs with struct-typed fields parse nested JSON objects automatically.\n//\nstruct Address {\n  city: text,\n  zip: text\n}\n\nstruct Contact {\n  name: text,\n  address: Address\n}\n\nfn main() {\n  u = User { id: 42, name: \"Alice\", email: \"alice@example.com\" };\n  json = \"{u:j}\";\n  expected = `{{\"id\":42,\"name\":\"Alice\",\"email\":\"alice@example.com\"}}`;\n  assert(json == expected, \"to json\");\n\n  bob = User.parse(`{{\"id\":7,\"name\":\"Bob\",\"email\":\"bob@test.org\"}}`);\n  assert(bob.id == 7, \"parsed id: {bob.id}\");\n  assert(bob.name == \"Bob\", \"parsed name\");\n  assert(bob.email == \"bob@test.org\", \"parsed email\");\n\n  u2 = User.parse(\"{u:j}\");\n  assert(u2.id == u.id, \"round-trip id\");\n  assert(u2.name == u.name, \"round-trip name\");\n\n  bad = User.parse(`{{\"id\":\"not_a_number\",\"name\":42}}`);\n  errs = 0;\n  for err in bad#errors {\n    log_info(\"parse error: {err}\");\n    errs += 1;\n  }\n  assert(errs > 0, \"expected parse errors, got {errs}\");\n\n  scores = vector<Score>.parse(`[{{\"value\":10}},{{\"value\":20}},{{\"value\":30}}]`);\n  total = 0;\n  for s in scores {\n    total += s.value;\n  }\n  assert(total == 60, \"vector sum: {total}\");\n\n  c = Contact.parse(`{{\"name\":\"Carol\",\"address\":{{\"city\":\"Amsterdam\",\"zip\":\"1012\"}}}}`);\n  assert(c.name == \"Carol\", \"nested name\");\n  assert(c.address.city == \"Amsterdam\", \"nested city: {c.address.city}\");\n  assert(c.address.zip == \"1012\", \"nested zip\");\n\n  // ## Missing fields get null\n  // When a field is absent from the JSON, the struct field gets its null sentinel.\n  // For text, that is the NUL character '\\0' (not the empty string \"\"); for integer\n  // it is the minimum i32 value. Check with '!' before use, or assign a default with '??'.\n  partial = User.parse(`{{\"id\":1}}`);\n  assert(partial.id == 1, \"partial id\");\n  assert(!partial.name, \"missing name is null\");\n}",
          "generics": "fn identity<T>(x: T) -> T { x }\n// ## Calling a generic function\n// No special syntax at the call site — the compiler infers T from the first\n// argument's type and creates a specialised copy automatically.\nfn test_identity() {\n  assert(identity(42) == 42, \"identity integer\");\n  assert(identity(3.14) == 3.14, \"identity float\");\n  assert(identity(\"hello\") == \"hello\", \"identity text\");\n  assert(identity(true) == true, \"identity bool\");\n}\n// ## Multiple parameters of the same type\n// Additional parameters can also use T.  They all share the same concrete type.\nfn pick_second<T>(gen_a: T, gen_b: T) -> T {\n  _x = gen_a;\n  gen_b\n}\nfn test_pick_second() {\n  assert(pick_second(1, 99) == 99, \"pick second int\");\n  assert(pick_second(\"a\", \"b\") == \"b\", \"pick second text\");\n}\n// ## Generic functions on vectors\n// The most common use of generics: write a function that works on any vector.\n// T is inferred from the vector's element type.\nfn first_element<T>(gen_v: vector<T>) -> T {\n  gen_v[0]\n}\nfn last_element<T>(gen_v: vector<T>) -> T {\n  gen_v[gen_v.len() - 1]\n}\nfn test_vector_generics() {\n  ints = [10, 20, 30];\n  assert(first_element(ints) == 10, \"first int\");\n  assert(last_element(ints) == 30, \"last int\");\n  words = [\"alpha\", \"beta\", \"gamma\"];\n  assert(first_element(words) == \"alpha\", \"first text\");\n  assert(last_element(words) == \"gamma\", \"last text\");\n}\n// ## Bounded generics with interfaces\n// By default, you can only assign and return T — no arithmetic, no comparison.\n// To use operators on T, add an interface bound: `<T: Ordered>` means T must\n// support `<`, `<=`, `>`, `>=` comparisons.\n//\n// Built-in interfaces:\n//   Ordered    — comparison operators (<, <=, >, >=)\n//   Equatable  — equality operators (==, !=)\n//   Addable    — addition and subtraction (+, -)\n//   Numeric    — all arithmetic (+, -, *, /, %)\n//   Scalable   — multiplication by integer (* integer)\nfn gen_max<T: Ordered>(gen_x: T, gen_y: T) -> T {\n  if gen_x > gen_y { gen_x } else { gen_y }\n}\nfn gen_min<T: Ordered>(gen_x: T, gen_y: T) -> T {\n  if gen_x < gen_y { gen_x } else { gen_y }\n}\nfn test_bounded() {\n  assert(gen_max(3, 7) == 7, \"max int\");\n  assert(gen_max(2.5, 1.5) == 2.5, \"max float\");\n  assert(gen_min(3, 7) == 3, \"min int\");\n  assert(gen_min(\"apple\", \"banana\") == \"apple\", \"min text\");\n}\n// ## Combining bounds\n// Use `+` to require multiple interfaces: `<T: Ordered + Addable>`.\nfn clamped_add<T: Ordered + Addable>(gen_a: T, gen_b: T, gen_hi: T) -> T {\n  result = gen_a + gen_b;\n  if result > gen_hi { gen_hi } else { result }\n}\nfn test_combined_bounds() {\n  assert(clamped_add(3, 4, 10) == 7, \"under limit\");\n  assert(clamped_add(8, 5, 10) == 10, \"clamped to limit\");\n  assert(clamped_add(1.0, 2.0, 2.5) == 2.5, \"float clamped\");\n}\n// ## Allowed operations on T\n// Inside a generic function you may only use operations that the bound\n// guarantees.  Without any bound: assign, return, store in variables.\n// With Ordered: comparisons.  With Addable: + and -.\n// ## Disallowed operations\n// The compiler rejects operations not covered by the bound.\n// `x + y` on unbounded T gives:\n//   \"generic type T: operator '+' requires a concrete type\"\n// `x.field` on T gives:\n//   \"generic type T: field access requires a concrete type\"\nfn main() {\n  test_identity();\n  test_pick_second();\n  test_vector_generics();\n  test_bounded();\n  test_combined_bounds();\n}",
          "closures": "fn make_adder(base_val: integer) -> fn(integer) -> integer {\n  fn(n: integer) -> integer { base_val + n }\n}\n\nfn main() {\n  // ## Integer capture\n  offset = 100;\n  shift = fn(x: integer) -> integer { x + offset };\n  assert(shift(5) == 105, \"shift(5): {shift(5)}\");\n  assert(shift(-3) == 97, \"shift(-3): {shift(-3)}\");\n\n  // ## Multiple integer captures\n  lo = 10;\n  hi = 20;\n  clamp_val = fn(x: integer) -> integer {\n    if x < lo { lo } else if x > hi { hi } else { x }\n  };\n  assert(clamp_val(5) == 10, \"clamp below: {clamp_val(5)}\");\n  assert(clamp_val(15) == 15, \"clamp mid: {clamp_val(15)}\");\n  assert(clamp_val(25) == 20, \"clamp above: {clamp_val(25)}\");\n\n  // ## Text capture\n  greeting = \"Hello\";\n  make_msg = fn(name: text) -> text { \"{greeting}, {name}!\" };\n  assert(make_msg(\"World\") == \"Hello, World!\", \"greeting capture\");\n  assert(make_msg(\"Loft\") == \"Hello, Loft!\", \"greeting capture 2\");\n\n  // ## Capture timing\n  // Closures capture at definition time. 'base' is 10 when the lambda is\n  // written; reassigning 'base' to 20 afterwards does not affect the\n  // captured value.\n  base = 10;\n  add_base = fn(n: integer) -> integer { base + n };\n  base = 20;\n  assert(add_base(5) == 15, \"sees base=10 at definition time: {add_base(5)}\");\n\n  // ## Cross-scope closures\n  // make_adder returns a lambda that captured base_val from its parameter.\n  add10 = make_adder(10);\n  add100 = make_adder(100);\n  assert(add10(5) == 15, \"add10(5): {add10(5)}\");\n  assert(add100(5) == 105, \"add100(5): {add100(5)}\");\n\n  // ## Closures with higher-order functions\n  factor = 3;\n  scale = fn(x: integer) -> integer { x * factor };\n  assert(scale(5) == 15, \"scale(5): {scale(5)}\");\n  assert(scale(10) == 30, \"scale(10): {scale(10)}\");\n\n  // ## Non-capturing lambdas with higher-order functions\n  // No capture needed here — the lambda uses only its own parameter.\n  nums = [1, 2, 3, 4, 5];\n  doubled = map(nums, |x| { x * 2 });\n  assert(doubled[0] == 2, \"doubled[0]: {doubled[0]}\");\n  assert(doubled[4] == 10, \"doubled[4]: {doubled[4]}\");\n\n  evens = filter(nums, |x| { x % 2 == 0 });\n  assert(evens[0] == 2, \"evens[0]: {evens[0]}\");\n  assert(evens[1] == 4, \"evens[1]: {evens[1]}\");\n}",
          "coroutines": "fn count_up(start: integer, stop: integer) -> iterator<integer> {\n  for i in start..stop {\n    yield i;\n  }\n}\n\nfn squares(n: integer) -> iterator<integer> {\n  for i in 1..=n {\n    yield i * i;\n  }\n}\n\n// Yields the length of 's' twice — shows that a text parameter survives yields.\nfn len_twice(s: text) -> iterator<integer> {\n  yield len(s);\n  yield len(s);\n}\n\nfn inner_vals() -> iterator<integer> {\n  yield 10;\n  yield 20;\n}\n\nfn outer_combined() -> iterator<integer> {\n  yield 1;\n  yield from inner_vals();\n  yield 2;\n}\n\nfn large_range(limit: integer) -> iterator<integer> {\n  for i in 1..=limit {\n    yield i;\n  }\n}\n\nfn main() {\n  // ## Iterating with a for loop\n  total = 0;\n  for n in count_up(1, 6) {\n    total += n;\n  }\n  assert(total == 15, \"sum 1..5: {total}\");\n\n  // Squares via for loop with index tracking.\n  idx = 0;\n  for s in squares(4) {\n    idx += 1;\n    if idx == 1 { assert(s == 1, \"sq1: {s}\"); }\n    if idx == 2 { assert(s == 4, \"sq2: {s}\"); }\n    if idx == 3 { assert(s == 9, \"sq3: {s}\"); }\n    if idx == 4 { assert(s == 16, \"sq4: {s}\"); }\n  }\n  assert(idx == 4, \"squares count: {idx}\");\n\n  // ## Manual advance with next() and exhausted()\n  gen = count_up(10, 13);\n  a = next(gen);\n  b = next(gen);\n  c = next(gen);\n  assert(a == 10 && b == 11 && c == 12, \"manual next: {a},{b},{c}\");\n  // One extra advance past the last element; exhausted() is true after that.\n  d = next(gen);\n  done = exhausted(gen);\n  assert(done, \"exhausted after last value\");\n\n  // ## Generators with parameters\n  // 'len_twice' takes a text parameter and yields its length twice.\n  // The text value is preserved across the yield.\n  lt_total = 0;\n  for n in len_twice(\"hello\") {\n    lt_total += n;\n  }\n  assert(lt_total == 10, \"len_twice: {lt_total}\");\n\n  // ## Delegation with yield from\n  yf_total = 0;\n  for n in outer_combined() {\n    yf_total += n;\n  }\n  assert(yf_total == 33, \"yield from: 1+10+20+2={yf_total}\");\n\n  // ## Early termination with break\n  // Stop after the first 5 values from a 1000-element generator.\n  limit_total = 0;\n  for n in large_range(1000) {\n    if n > 5 { break; }\n    limit_total += n;\n  }\n  assert(limit_total == 15, \"early break sum 1..5: {limit_total}\");\n}",
          "tuples": "fn min_max(lo: integer, hi: integer) -> (integer, integer) {\n  if lo <= hi {\n    (lo, hi)\n  } else {\n    (hi, lo)\n  }\n}\n\nfn swap_ints(pair: &(integer, integer)) {\n  tmp = pair.0;\n  pair.0 = pair.1;\n  pair.1 = tmp;\n}\n\nfn main() {\n  // ## Creating tuples\n  t = (10, 20);\n  assert(t.0 == 10, \"t.0: {t.0}\");\n  assert(t.1 == 20, \"t.1: {t.1}\");\n\n  // Type annotation\n  w: (integer, integer) = (3, 4);\n  assert(w.0 + w.1 == 7, \"annotated sum: {w.0+w.1}\");\n\n  // ## Modifying elements\n  v = (1, 2);\n  v.0 = 10;\n  assert(v.0 + v.1 == 12, \"after assign: {v.0}+{v.1}\");\n\n  // ## Tuples as value parameters\n  p = (10, 20);\n  sum = p.0 + p.1;\n  assert(sum == 30, \"sum: {sum}\");\n\n  // ## Tuples as reference parameters (swap in place)\n  pair = (3, 7);\n  swap_ints(pair);\n  assert(pair.0 == 7 && pair.1 == 3, \"after swap: ({pair.0},{pair.1})\");\n\n  // ## Returning a tuple from a function\n  bounds = min_max(5, 2);\n  assert(bounds.0 == 2, \"min: {bounds.0}\");\n  assert(bounds.1 == 5, \"max: {bounds.1}\");\n\n  // Already in order\n  bounds2 = min_max(1, 9);\n  assert(bounds2.0 == 1, \"min2: {bounds2.0}\");\n  assert(bounds2.1 == 9, \"max2: {bounds2.1}\");\n\n  // ## Destructuring\n  (lo, hi) = min_max(8, 3);\n  assert(lo == 3, \"destructured lo: {lo}\");\n  assert(hi == 8, \"destructured hi: {hi}\");\n\n  // ## Three or more elements\n  u = (1, 2, 3);\n  assert(u.0 + u.1 + u.2 == 6, \"triple sum: {u.0}+{u.1}+{u.2}\");\n\n  triple = (10, 20, 30);\n  triple.1 = 99;\n  assert(triple.0 == 10 && triple.1 == 99 && triple.2 == 30,\n    \"triple modified: ({triple.0},{triple.1},{triple.2})\");\n}",
          "match": "enum Direction { North, South, East, West }\n\nfn direction_name(d: Direction) -> text {\n  match d {\n    North => \"north\",\n    South => \"south\",\n    East  => \"east\",\n    West  => \"west\",\n  }\n}\n\nfn main() {\n  assert(direction_name(North) == \"north\", \"simple enum match\");\n  assert(direction_name(West) == \"west\", \"west\");\n  // ## Match as expression\n  // Because match returns a value you can use it in assignments and arguments.\n  score = match Direction.East {\n    North | South => 10,\n    East | West   => 20,\n  };\n  assert(score == 20, \"match expression: {score}\");\n  // ## Struct-enum destructuring\n  // When an enum has variants with fields (a struct-enum) you can bind the\n  // fields to variables in the match arm.\n  //   Circle { radius } — binds the 'radius' field to a local variable\n  //   Rect { w, h }     — binds both 'w' and 'h'\n  // The variable names must match the field names exactly.\n  // ## Guards\n  // Add `if condition` after a pattern to restrict when the arm matches.\n  // The guard can reference variables bound by the pattern.\n  v = 42;\n  label = match v {\n    0      => \"zero\",\n    _ if v < 0 => \"negative\",\n    _ if v > 100 => \"large\",\n    _      => \"normal\",\n  };\n  assert(label == \"normal\", \"guard: {label}\");\n  // ## Wildcard `_`\n  // The underscore `_` matches anything.  Put it last as a catch-all.\n  // Without it, the compiler will reject the match if any value could\n  // fall through without matching.\n  x = 7;\n  kind = match x {\n    1 => \"one\",\n    2 => \"two\",\n    _ => \"other\",\n  };\n  assert(kind == \"other\", \"wildcard: {kind}\");\n  // ## Integer matching\n  // Match works on integers — each arm is compared with `==`.\n  name = match 3 {\n    1 => \"one\",\n    2 => \"two\",\n    3 => \"three\",\n    _ => \"many\",\n  };\n  assert(name == \"three\", \"integer match: {name}\");\n  // ## Text matching\n  // Match also works on text values.\n  greeting = \"hi\";\n  reply = match greeting {\n    \"hello\" => \"formal\",\n    \"hi\"    => \"casual\",\n    _       => \"unknown\",\n  };\n  assert(reply == \"casual\", \"text match: {reply}\");\n  // ## Multiple patterns with `|`\n  // Combine patterns with `|` to share the same arm body.\n  d = Direction.South;\n  axis = match d {\n    North | South => \"vertical\",\n    East | West   => \"horizontal\",\n  };\n  assert(axis == \"vertical\", \"multi-pattern: {axis}\");\n  // ## Nested match\n  // Match can appear inside other expressions, including other match arms.\n  n = 15;\n  result = match n % 2 == 0 {\n    true  => \"even\",\n    false => match n % 3 == 0 {\n      true  => \"odd multiple of 3\",\n      false => \"odd\",\n    },\n  };\n  assert(result == \"odd multiple of 3\", \"nested: {result}\");\n}",
          "fizzbuzz": "fn main() {\n  println(\"Hello from Loft!\");\n\n  for i in 1..21 {\n    if i % 3 == 0 and i % 5 == 0 {\n      println(\"FizzBuzz\");\n    } else if i % 3 == 0 {\n      println(\"Fizz\");\n    } else if i % 5 == 0 {\n      println(\"Buzz\");\n    } else {\n      println(\"{i}\");\n    }\n  }\n}",
          "perf_fibonacci": "// Recursive Fibonacci\nfn fib(n: integer) -> integer {\n  if n <= 1 { n } else { fib(n - 1) + fib(n - 2) }\n}\n\nfn main() {\n  t0 = ticks();\n  r = fib(30);\n  ms = (ticks() - t0) / 1000l;\n  println(\"fib(30) = {r}\");\n  println(\"time: {ms} ms\");\n  assert(r == 832040);\n}",
          "perf_sieve": "// Count primes up to 10,000 (trial division)\nfn is_prime(n: integer) -> boolean {\n  if n < 2 { return false; }\n  if n == 2 { return true; }\n  if n % 2 == 0 { return false; }\n  i = 3;\n  for _ in 0..n {\n    if i * i > n { break; }\n    if n % i == 0 { return false; }\n    i += 2;\n  }\n  true\n}\n\nfn main() {\n  limit = 10000;\n  t0 = ticks();\n  count = 0;\n  for n in 0..limit {\n    if is_prime(n) {\n      count += 1;\n    }\n  }\n  ms = (ticks() - t0) / 1000l;\n  println(\"primes below {limit}: {count}\");\n  println(\"time: {ms} ms\");\n  assert(count == 1229);\n}",
          "perf_mandelbrot": "// Mandelbrot set (100x100, max 256 iterations)\nfn mandelbrot(cx: float, cy: float) -> integer {\n  zx = 0.0;\n  zy = 0.0;\n  for mb_i in 0..256 {\n    if zx * zx + zy * zy > 4.0 { return mb_i; }\n    tmp = zx * zx - zy * zy + cx;\n    zy = 2.0 * zx * zy + cy;\n    zx = tmp;\n  }\n  256\n}\n\nfn main() {\n  size = 100;\n  t0 = ticks();\n  total = 0;\n  for mb_y in 0..size {\n    for mb_x in 0..size {\n      cx = (mb_x as float / size as float) * 3.5 - 2.5;\n      cy = (mb_y as float / size as float) * 2.0 - 1.0;\n      total += mandelbrot(cx, cy);\n    }\n  }\n  ms = (ticks() - t0) / 1000l;\n  println(\"total iterations: {total}\");\n  println(\"time: {ms} ms\");\n}",
          "perf_collatz": "// Longest Collatz sequence (1..100,000)\nfn collatz_len(start: long) -> integer {\n  cur = start;\n  steps = 1;\n  for _ in 0..10000000 {\n    if cur == 1l { break; }\n    if cur % 2l == 0l { cur = cur / 2l; }\n    else { cur = 3l * cur + 1l; }\n    steps += 1;\n  }\n  steps\n}\n\nfn main() {\n  n = 100000;\n  t0 = ticks();\n  max_steps = 0;\n  max_n = 0l;\n  for col_i in 1..n {\n    s = collatz_len(col_i as long);\n    if s > max_steps {\n      max_steps = s;\n      max_n = col_i as long;\n    }\n  }\n  ms = (ticks() - t0) / 1000l;\n  println(\"longest chain: {max_n} ({max_steps} steps)\");\n  println(\"time: {ms} ms\");\n}",
          "formatting": "fn main() {\n  name = \"world\";\n  assert(\"hello {name}\" == \"hello world\", \"basic interpolation\");\n  assert(\"1 + 2 = {1 + 2}\" == \"1 + 2 = 3\", \"expression in braces\");\n  // ## Width and alignment\n  // A number after `:` sets the minimum width.  The value is padded with\n  // spaces to fill the width.\n  //   {val:6}   — right-aligned (default for numbers)\n  //   {val:>6}  — right-aligned (explicit)\n  //   {val:<6}  — left-aligned\n  //   {val:^6}  — centered\n  // For text, the default alignment is left.  For numbers, right.\n  assert(\"{42:6}\" == \"    42\", \"default number align is right\");\n  assert(\"{42:>6}\" == \"    42\", \"explicit right-align\");\n  assert(\"{42:<6}\" == \"42    \", \"left-align number\");\n  assert(\"{42:^6}\" == \"  42  \", \"center-align number\");\n  s = \"hi\";\n  assert(\"{s:6}\" == \"hi    \", \"default text align is left\");\n  assert(\"{s:>6}\" == \"    hi\", \"right-align text\");\n  assert(\"{s:^6}\" == \"  hi  \", \"center-align text\");\n  // ## Zero padding\n  // Prefix the width with `0` to pad with zeros instead of spaces.\n  assert(\"{7:03}\" == \"007\", \"zero-padded 3 digits\");\n  assert(\"{42:05}\" == \"00042\", \"zero-padded 5 digits\");\n  assert(\"{-1:04}\" == \"-001\", \"zero-padded negative: sign before zeros\");\n  // ## Signed format\n  // `+` forces a sign on positive numbers.\n  assert(\"{42:+}\" == \"+42\", \"explicit positive sign\");\n  assert(\"{-42:+}\" == \"-42\", \"negative sign always shown\");\n  assert(\"{0:+}\" == \"+0\", \"sign on zero\");\n  // ## Hexadecimal, binary, octal\n  // `:x` for lowercase hex, `:#x` for hex with `0x` prefix.\n  // `:b` for binary, `:o` for octal.\n  assert(\"{255:x}\" == \"ff\", \"hex lowercase\");\n  assert(\"{255:#x}\" == \"0xff\", \"hex with prefix\");\n  assert(\"{10:b}\" == \"1010\", \"binary\");\n  assert(\"{8:o}\" == \"10\", \"octal\");\n  // ## Float precision\n  // `.N` after the colon limits decimal places.\n  assert(\"{3.125:.1}\" == \"3.1\", \"1 decimal place\");\n  assert(\"{3.125:.2}\" == \"3.12\", \"2 decimal places\");\n  assert(\"{3.125:.0}\" == \"3\", \"0 decimal places\");\n  assert(\"{0.0:.3}\" == \"0.000\", \"trailing zeros\");\n  // ## Width + precision\n  // Combine width and precision: `{val:W.P}` where W is total width\n  // and P is decimal places.\n  assert(\"{3.125:8.2}\" == \"    3.12\", \"width 8 precision 2\");\n  assert(\"{-3.125:8.2}\" == \"   -3.12\", \"negative width+precision\");\n  // ## JSON format\n  // `:j` serialises a struct or value as JSON.\n  // `:j` serialises a struct as JSON.  Use it on struct values, not primitives.\n  // See the JSON documentation page for full details.\n  // ## Vector format\n  // Vectors are formatted as `[a,b,c]` by default.\n  // A format specifier inside a `for` loop applies to each element.\n  v = [1, 2, 3];\n  assert(\"{v}\" == \"[1,2,3]\", \"default vector format\");\n  assert(\"{for fmt_n in 1..4 {fmt_n * 10}:04}\" == \"[0010,0020,0030]\", \"formatted vector elements\");\n  // ## Long and single types\n  // Long integers and single-precision floats use the same format specifiers.\n  n = 1000000l;\n  assert(\"{n}\" == \"1000000\", \"long default\");\n  assert(\"{n:>10}\" == \"   1000000\", \"long right-aligned\");\n  f = 1.5f;\n  assert(\"{f}\" == \"1.5\", \"single default\");\n  // ## Character format\n  c = 'A';\n  assert(\"{c}\" == \"A\", \"character default\");\n  // ## Boolean format\n  assert(\"{true}\" == \"true\", \"boolean true\");\n  assert(\"{false}\" == \"false\", \"boolean false\");\n}",
      };
